import React, { useState } from 'react';
import { Sparkles, Download, RefreshCw } from 'lucide-react';
import { generateDesignImage } from '../services/geminiService';
import { AspectRatio, GeneratedImage } from '../types';
import { Button } from './Button';

interface GeneratorProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Generator: React.FC<GeneratorProps> = ({ onImageGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;

    setIsGenerating(true);
    try {
      const base64Image = await generateDesignImage(prompt, aspectRatio);
      setCurrentImage(base64Image);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: base64Image,
        prompt: prompt,
        mode: 'creation',
        timestamp: Date.now()
      };

      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to generate design. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const downloadImage = () => {
    if (currentImage) {
      const link = document.createElement('a');
      link.href = currentImage;
      link.download = `prhomz-design-${Date.now()}.png`;
      link.click();
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-white">Design Creation</h2>
        <p className="text-brand-300">Visualize your dream space with AI-powered generation.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <form onSubmit={handleGenerate} className="space-y-6 bg-brand-900/50 p-6 rounded-2xl border border-brand-800">
            <div className="space-y-2">
              <label className="text-sm font-medium text-brand-200">Describe your vision</label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="E.g., A minimalist living room with floor-to-ceiling windows overlooking a forest, warm lighting, beige sectional sofa..."
                className="w-full h-32 bg-brand-950 border border-brand-700 rounded-lg p-4 text-white placeholder-brand-600 focus:ring-2 focus:ring-brand-500 focus:border-transparent resize-none"
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-brand-200">Aspect Ratio</label>
              <div className="grid grid-cols-3 gap-2">
                {(['16:9', '1:1', '9:16'] as AspectRatio[]).map((ratio) => (
                  <button
                    key={ratio}
                    type="button"
                    onClick={() => setAspectRatio(ratio)}
                    className={`
                      py-2 px-3 rounded-md text-sm font-medium transition-colors
                      ${aspectRatio === ratio 
                        ? 'bg-brand-700 text-white border border-brand-500' 
                        : 'bg-brand-950 text-brand-400 border border-brand-800 hover:border-brand-600'}
                    `}
                  >
                    {ratio}
                  </button>
                ))}
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full py-3" 
              isLoading={isGenerating}
              disabled={!prompt.trim()}
            >
              <Sparkles className="w-4 h-4 mr-2" />
              Generate Design
            </Button>
          </form>

          {/* Inspiration Tags */}
          <div className="flex flex-wrap gap-2">
            {['Modern Rustic', 'Scandinavian', 'Industrial Loft', 'Japandi', 'Art Deco'].map(tag => (
              <button
                key={tag}
                onClick={() => setPrompt(prev => prev + (prev ? ' ' : '') + tag)}
                className="px-3 py-1 bg-brand-900/30 text-xs text-brand-400 rounded-full border border-brand-800 hover:bg-brand-800 hover:text-brand-200 transition-colors"
              >
                + {tag}
              </button>
            ))}
          </div>
        </div>

        <div className="relative group min-h-[400px] flex items-center justify-center bg-brand-950 rounded-2xl border-2 border-dashed border-brand-800 overflow-hidden">
          {currentImage ? (
            <div className="relative w-full h-full">
              <img 
                src={currentImage} 
                alt="Generated Design" 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-4">
                <Button variant="secondary" onClick={downloadImage}>
                  <Download className="w-4 h-4 mr-2" />
                  Download
                </Button>
              </div>
            </div>
          ) : (
            <div className="text-center text-brand-600 p-8">
              {isGenerating ? (
                <div className="animate-pulse space-y-4">
                  <div className="w-16 h-16 bg-brand-800 rounded-full mx-auto"></div>
                  <div className="text-sm">Creating your masterpiece...</div>
                </div>
              ) : (
                <>
                  <Sparkles className="w-12 h-12 mx-auto mb-4 opacity-50" />
                  <p>Your design will appear here</p>
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Upload, Paintbrush, Download, ArrowRight } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage } from '../types';
import { Button } from './Button';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null); // Clear previous result
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || !instruction.trim()) return;

    setIsProcessing(true);
    try {
      const outputBase64 = await remodelImage(previewUrl, instruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Edited: ${instruction}`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-white">Room Remodeler</h2>
        <p className="text-brand-300">Upload a photo and give instructions to transform it.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Input Section */}
        <div className="space-y-6">
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`
              relative h-64 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center cursor-pointer transition-all
              ${previewUrl 
                ? 'border-brand-700 bg-brand-950' 
                : 'border-brand-600 bg-brand-900/30 hover:bg-brand-900/50 hover:border-brand-500'}
            `}
          >
            {previewUrl ? (
              <img src={previewUrl} alt="Original" className="w-full h-full object-contain rounded-xl p-2" />
            ) : (
              <div className="text-center p-6 space-y-2 text-brand-400">
                <Upload className="w-10 h-10 mx-auto mb-2" />
                <p className="font-medium">Click to upload photo</p>
                <p className="text-xs text-brand-500">JPG, PNG up to 5MB</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange}
              accept="image/*"
              className="hidden" 
            />
          </div>

          <form onSubmit={handleRemodel} className="space-y-4">
            <div className="relative">
              <input
                type="text"
                value={instruction}
                onChange={(e) => setInstruction(e.target.value)}
                placeholder="E.g., Change the wall color to sage green"
                className="w-full bg-brand-900 border border-brand-700 rounded-lg py-3 px-4 pr-12 text-white placeholder-brand-600 focus:ring-2 focus:ring-brand-500 focus:outline-none"
              />
              <Paintbrush className="absolute right-4 top-3.5 w-5 h-5 text-brand-500" />
            </div>

            <Button 
              type="submit" 
              className="w-full" 
              isLoading={isProcessing}
              disabled={!previewUrl || !instruction.trim()}
            >
              Transform Space
            </Button>
          </form>
        </div>

        {/* Result Section */}
        <div className="space-y-4">
          <div className="h-64 lg:h-[400px] bg-brand-950 rounded-2xl border border-brand-800 flex items-center justify-center relative overflow-hidden group">
            {resultImage ? (
              <>
                 <img src={resultImage} alt="Remodeled" className="w-full h-full object-contain" />
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <a 
                      href={resultImage} 
                      download={`prhomz-remodel-${Date.now()}.png`}
                      className="inline-flex items-center px-4 py-2 bg-brand-500 text-white rounded-lg hover:bg-brand-400 transition-colors"
                    >
                      <Download className="w-4 h-4 mr-2" />
                      Save Image
                    </a>
                  </div>
              </>
            ) : (
              <div className="text-brand-700 text-center p-8">
                {isProcessing ? (
                  <div className="space-y-4 animate-pulse">
                     <div className="w-12 h-12 border-4 border-brand-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                     <p>Redesigning your space...</p>
                  </div>
                ) : (
                  <>
                    <ArrowRight className="w-12 h-12 mx-auto mb-4 opacity-30" />
                    <p>The transformed result will appear here</p>
                  </>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot } from 'lucide-react';
import { chatWithArchitect } from '../services/geminiService';
import { ChatMessage } from '../types';

export const Assistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Hello. I am PRHOMZ, your design consultant. How can I assist with your interior project today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    // Prepare history for API
    const history = messages.map(m => ({ role: m.role, text: m.text }));

    try {
      const responseText = await chatWithArchitect(history, userMsg.text);
      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      // Error handled in service, but nice to show UI feedback
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto h-[calc(100vh-140px)] flex flex-col bg-brand-900/30 rounded-2xl border border-brand-800 overflow-hidden">
      {/* Header */}
      <div className="p-4 bg-brand-950 border-b border-brand-800 flex items-center space-x-3">
        <div className="p-2 bg-brand-800 rounded-lg">
          <Bot className="w-5 h-5 text-brand-300" />
        </div>
        <div>
          <h3 className="font-serif font-bold text-white">AI Architect</h3>
          <p className="text-xs text-brand-400">Expert design consultation</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`
              max-w-[80%] rounded-2xl p-4
              ${msg.role === 'user' 
                ? 'bg-brand-600 text-white rounded-br-sm' 
                : 'bg-brand-900 text-brand-100 border border-brand-800 rounded-bl-sm'}
            `}>
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-brand-900 rounded-2xl rounded-bl-sm p-4 border border-brand-800 flex space-x-2">
              <div className="w-2 h-2 bg-brand-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
              <div className="w-2 h-2 bg-brand-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
              <div className="w-2 h-2 bg-brand-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSend} className="p-4 bg-brand-950 border-t border-brand-800">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask about color schemes, furniture styles..."
            className="w-full bg-brand-900 border border-brand-700 text-white rounded-xl py-3 pl-4 pr-12 focus:ring-2 focus:ring-brand-500 focus:outline-none placeholder-brand-600"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 p-2 bg-brand-600 text-white rounded-lg hover:bg-brand-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </form>
    </div>
  );
