import { GoogleGenAI, Type } from "@google/genai";
import { Product, ProductSource } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * PRHOMZ.COM Implementation of the ProductSource interface.
 * Uses AI to simulate fetching products from the PRHOMZ catalog based on design queries.
 */
export class PrhomzProductSource implements ProductSource {
  vendorName = "PRHOMZ.COM";

  async searchProducts(query: string): Promise<Product[]> {
    try {
      // We use Gemini to generate a structured list of products that would conceptually 
      // exist in the PRHOMZ catalog matching the user's search.
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Generate a list of 6 premium interior design products that match the search query: "${query}". 
        These products must be attributed to the vendor "PRHOMZ.COM".
        For the image URL, generate a placeholder URL using https://placehold.co/600x400?text=[Product+Name] but URL encoded.
        Return realistic prices in USD.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                price: { type: Type.NUMBER },
                currency: { type: Type.STRING },
                category: { type: Type.STRING },
                imageUrl: { type: Type.STRING },
                sourceUrl: { type: Type.STRING },
                vendor: { type: Type.STRING },
              },
              required: ["id", "name", "description", "price", "currency", "imageUrl", "vendor"],
            },
          },
        }
      });

      if (response.text) {
        const products = JSON.parse(response.text) as Product[];
        // Ensure vendor is strictly set
        return products.map(p => ({
            ...p, 
            vendor: this.vendorName,
            sourceUrl: `https://prhomz.com/shop/${p.id}` 
        }));
      }

      return [];
    } catch (error) {
      console.error("Error sourcing products:", error);
      return [];
    }
  }
}

// Factory to get sources (extensible for future sources)
export const getProductSource = (): ProductSource => {
  return new PrhomzProductSource();
};

