          onClick={onClose}
          className="absolute top-4 right-4 z-20 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors"
        >
          <X size={20} />
        </button>

        {/* Left Side: Image */}
        <div className="w-full md:w-5/12 bg-brand-950 relative hidden md:block">
          <img src={image} alt="Design Reference" className="w-full h-full object-cover opacity-90" />
          <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-brand-950 to-transparent p-8">
            <h3 className="text-2xl font-serif text-white font-bold">Shop the Look</h3>
            <p className="text-brand-300 text-sm mt-1">Curated pieces from your design.</p>
          </div>
        </div>

        {/* Right Side: Products */}
        <div className="w-full md:w-7/12 flex flex-col h-full bg-brand-900">
          <div className="p-6 border-b border-brand-800 md:hidden">
            <h3 className="text-xl font-serif text-white font-bold">Shop the Look</h3>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-64 flex flex-col items-center justify-center text-brand-400 space-y-4">
                <Loader2 className="w-10 h-10 animate-spin text-brand-500" />
                <p>Analyzing design and sourcing products...</p>
              </div>
            ) : success ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6 animate-in fade-in zoom-in duration-300">
                <div className="w-20 h-20 bg-green-500/20 text-green-400 rounded-full flex items-center justify-center">
                  <Check size={40} />
                </div>
                <div>
                  <h3 className="text-2xl font-serif font-bold text-white mb-2">Order Confirmed!</h3>
                  <p className="text-brand-300">Your items are being prepared for shipping.</p>
                  <p className="text-brand-400 text-sm mt-4">Order #{Math.floor(Math.random() * 1000000)} • Total: ${totalPrice.toLocaleString()}</p>
                </div>
                <Button onClick={onClose} variant="secondary">Continue Designing</Button>
              </div>
            ) : (
              products.map((item) => (
                <div key={item.id} className="flex gap-4 bg-brand-950/50 p-4 rounded-xl border border-brand-800">
                  <div className="flex-1">
                    <div className="flex justify-between items-start">
                      <h4 className="font-serif text-lg font-medium text-white">{item.name}</h4>
                      <span className="font-mono text-brand-200">${item.price}</span>
                    </div>
                    <p className="text-sm text-brand-400 mt-1 mb-3">{item.description}</p>

                    <div className="space-y-2">
                      <span className="text-xs text-brand-500 uppercase tracking-wider font-bold">Select Color</span>
                      <div className="flex flex-wrap gap-2">
                        {item.colors.map((color) => {
                          const isSelected = selections[item.id] === color;
                          return (
                            <button
                              key={color}
                              onClick={() => handleColorSelect(item.id, color)}
                              className={`
