  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null); // Clear previous result
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || !instruction.trim()) return;

    setIsProcessing(true);
    try {
      const outputBase64 = await remodelImage(previewUrl, instruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Edited: ${instruction}`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-white">Room Remodeler</h2>
        <p className="text-brand-300">Upload a photo and give instructions to transform it.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Input Section */}
        <div className="space-y-6">
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`
              relative h-64 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center cursor-pointer transition-all
              ${previewUrl 
                ? 'border-brand-700 bg-brand-950' 
                : 'border-brand-600 bg-brand-900/30 hover:bg-brand-900/50 hover:border-brand-500'}
            `}
          >
            {previewUrl ? (
              <img src={previewUrl} alt="Original" className="w-full h-full object-contain rounded-xl p-2" />
            ) : (
              <div className="text-center p-6 space-y-2 text-brand-400">
                <Upload className="w-10 h-10 mx-auto mb-2" />
                <p className="font-medium">Click to upload photo</p>
                <p className="text-xs text-brand-500">JPG, PNG up to 5MB</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange}
              accept="image/*"
              className="hidden" 
            />
          </div>

          <form onSubmit={handleRemodel} className="space-y-4">
            <div className="relative">
              <input
                type="text"
                value={instruction}
                onChange={(e) => setInstruction(e.target.value)}
                placeholder="E.g., Change the wall color to sage green"
                className="w-full bg-brand-900 border border-brand-700 rounded-lg py-3 px-4 pr-12 text-white placeholder-brand-600 focus:ring-2 focus:ring-brand-500 focus:outline-none"
              />
              <Paintbrush className="absolute right-4 top-3.5 w-5 h-5 text-brand-500" />
            </div>

            <Button 
              type="submit" 
              className="w-full" 
              isLoading={isProcessing}
              disabled={!previewUrl || !instruction.trim()}
            >
              Transform Space
            </Button>
          </form>
        </div>

        {/* Result Section */}
        <div className="space-y-4">
          <div className="h-64 lg:h-[400px] bg-brand-950 rounded-2xl border border-brand-800 flex items-center justify-center relative overflow-hidden group">
            {resultImage ? (
              <div className="relative w-full h-full">
                 <img src={resultImage} alt="Remodeled" className="w-full h-full object-contain" />
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center space-y-3">
                     <Button 
                        onClick={() => setIsShopOpen(true)}
                        className="bg-white text-brand-900 hover:bg-brand-100 hover:text-brand-900 border-none shadow-xl transform hover:scale-105 transition-all"
                      >
                        <ShoppingBag className="w-4 h-4 mr-2" />
                        Shop This Look
                      </Button>
                      <a 
                        href={resultImage} 
                        download={`prhomz-remodel-${Date.now()}.png`}
                        className="inline-flex items-center px-4 py-2 bg-brand-500 text-white rounded-lg hover:bg-brand-400 transition-colors"
                      >
                        <Download className="w-4 h-4 mr-2" />
                        Save Image
                      </a>
                  </div>
              </div>
            ) : (
              <div className="text-brand-700 text-center p-8">
                {isProcessing ? (
                  <div className="space-y-4 animate-pulse">
                     <div className="w-12 h-12 border-4 border-brand-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                     <p>Redesigning your space...</p>
                  </div>
                ) : (
                  <>
                    <ArrowRight className="w-12 h-12 mx-auto mb-4 opacity-30" />
                    <p>The transformed result will appear here</p>
                  </>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {resultImage && (
        <ShopLookModal 
          image={resultImage} 
          isOpen={isShopOpen} 
          onClose={() => setIsShopOpen(false)} 
        />
      )}
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-500 disabled:opacity-50 disabled:cursor-not-allowed";

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  const variants = {
    primary: "bg-gradient-to-r from-brand-500 to-brand-600 hover:from-brand-400 hover:to-brand-500 text-white shadow-lg shadow-brand-900/50",
    secondary: "bg-brand-800 text-brand-100 hover:bg-brand-700 border border-brand-700",
    ghost: "bg-transparent text-brand-200 hover:text-white hover:bg-white/5"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className}`}
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center space-x-2">
          <svg className="animate-spin h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span>Processing...</span>
        </span>
      ) : children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, DollarSign } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [checkingOut, setCheckingOut] = useState(false);
  const [success, setSuccess] = useState(false);
  const [purchasingItems, setPurchasingItems] = useState<Set<string>>(new Set());
  const [purchasedItems, setPurchasedItems] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      // Reset state when closed
      setProducts([]);
      setSelections({});
      setSuccess(false);
      setCheckingOut(false);
      setPurchasingItems(new Set());
      setPurchasedItems(new Set());
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      // Initialize default colors
      const initialSelections: Record<string, string> = {};
      items.forEach(item => {
        if (item.colors.length > 0) {
          initialSelections[item.id] = item.colors[0];
        }
      });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleBulkCheckout = () => {
    setCheckingOut(true);
    setTimeout(() => {
      setCheckingOut(false);
      setSuccess(true);
    }, 1500);
  };

  const handleSingleCheckout = (itemId: string) => {
    setPurchasingItems(prev => new Set(prev).add(itemId));
    setTimeout(() => {
      setPurchasingItems(prev => {
        const next = new Set(prev);
        next.delete(itemId);
        return next;
      });
      setPurchasedItems(prev => new Set(prev).add(itemId));
    }, 1000);
  };

  if (!isOpen) return null;

  const totalPrice = products.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-brand-900 w-full max-w-5xl rounded-2xl shadow-2xl border border-brand-700 flex flex-col md:flex-row overflow-hidden max-h-[90vh]">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-20 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors"
        >
          <X size={20} />
        </button>

        {/* Left Side: Image */}
        <div className="w-full md:w-5/12 bg-brand-950 relative hidden md:block">
          <img src={image} alt="Design Reference" className="w-full h-full object-cover opacity-90" />
          <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-brand-950 to-transparent p-8">
            <h3 className="text-2xl font-serif text-white font-bold">Shop the Look</h3>
            <p className="text-brand-300 text-sm mt-1">Curated pieces from your design.</p>
          </div>
        </div>

        {/* Right Side: Products */}
        <div className="w-full md:w-7/12 flex flex-col h-full bg-brand-900">
          <div className="p-6 border-b border-brand-800 md:hidden">
            <h3 className="text-xl font-serif text-white font-bold">Shop the Look</h3>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-64 flex flex-col items-center justify-center text-brand-400 space-y-4">
                <Loader2 className="w-10 h-10 animate-spin text-brand-500" />
                <p>Analyzing design and sourcing products...</p>
              </div>
            ) : success ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6 animate-in fade-in zoom-in duration-300">
                <div className="w-20 h-20 bg-green-500/20 text-green-400 rounded-full flex items-center justify-center">
                  <Check size={40} />
                </div>
                <div>
                  <h3 className="text-2xl font-serif font-bold text-white mb-2">Order Confirmed!</h3>
                  <p className="text-brand-300">Your collection is being prepared.</p>
                  <p className="text-brand-400 text-sm mt-4">Order #{Math.floor(Math.random() * 1000000)}</p>
                </div>
                <Button onClick={onClose} variant="secondary">Continue Designing</Button>
              </div>
            ) : (
              products.map((item) => {
                const isPurchased = purchasedItems.has(item.id);
                const isPurchasing = purchasingItems.has(item.id);

                return (
                  <div key={item.id} className="flex gap-4 bg-brand-950/50 p-4 rounded-xl border border-brand-800 transition-all hover:border-brand-700">
                    <div className="flex-1 space-y-3">
                      <div className="flex justify-between items-start">
                        <div>
                           <h4 className="font-serif text-lg font-medium text-white">{item.name}</h4>
                           <p className="text-sm text-brand-400 mt-0.5">{item.description}</p>
                        </div>
                        <span className="font-mono text-lg text-brand-200 font-medium">${item.price}</span>
                      </div>

                      <div className="pt-2 flex flex-col sm:flex-row sm:items-end justify-between gap-4">
                        <div className="space-y-2">
                          <span className="text-[10px] text-brand-500 uppercase tracking-widest font-bold">Available Colors</span>
                          <div className="flex flex-wrap gap-2">
                            {item.colors.map((color) => {
                              const isSelected = selections[item.id] === color;
                              return (
                                <button
                                  key={color}
                                  onClick={() => !isPurchased && handleColorSelect(item.id, color)}
                                  disabled={isPurchased}
                                  className={`
                                    px-3 py-1 rounded-md text-xs font-medium transition-all border
                                    ${isSelected 
                                      ? 'bg-brand-700 border-brand-500 text-white shadow-sm' 
                                      : 'bg-brand-900 border-brand-800 text-brand-400 hover:border-brand-600'}
                                    ${isPurchased ? 'opacity-50 cursor-default' : 'cursor-pointer'}
                                  `}
                                >
                                  {color}
                                </button>
                              );
                            })}
                          </div>
                        </div>

                        <Button 
                          variant={isPurchased ? "ghost" : "secondary"}
                          size="sm"
                          onClick={() => handleSingleCheckout(item.id)}
                          isLoading={isPurchasing}
                          disabled={isPurchased}
                          className={isPurchased ? "text-green-500" : ""}
                        >
                          {isPurchased ? (
                            <>
                              <Check className="w-4 h-4 mr-1" />
                              Purchased
                            </>
                          ) : (
                            <>
                              <CreditCard className="w-3 h-3 mr-2" />
                              One Click Checkout
                            </>
                          )}
                        </Button>
                      </div>
                    </div>
                  </div>
                );
              })
            )}

            {!loading && !success && products.length === 0 && (
              <div className="text-center py-12 text-brand-400">
                <ShoppingBag className="w-12 h-12 mx-auto mb-3 opacity-30" />
                <p>Could not identify specific products in this image.</p>
              </div>
            )}
          </div>

          {!loading && !success && products.length > 0 && (
            <div className="p-6 bg-brand-950 border-t border-brand-800">
              <div className="flex justify-between items-center mb-6">
                <span className="text-brand-300">Total ({products.length} items)</span>
                <span className="text-3xl font-serif font-bold text-white">${totalPrice.toLocaleString()}</span>
              </div>
              <Button 
                onClick={handleBulkCheckout} 
                className="w-full py-4 text-lg"
                size="lg"
                isLoading={checkingOut}
              >
                {!checkingOut && <ShoppingBag className="mr-2 h-5 w-5" />}
                Checkout All Products
              </Button>
              <p className="text-center text-xs text-brand-500 mt-3 flex items-center justify-center">
                 <Check className="w-3 h-3 mr-1" /> Secure 1-Click Checkout active
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sparkles, Download, ShoppingBag, DollarSign } from 'lucide-react';
import { generateDesignImage } from '../services/geminiService';
import { AspectRatio, GeneratedImage } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface GeneratorProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Generator: React.FC<GeneratorProps> = ({ onImageGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [budget, setBudget] = useState(5000);
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);

  const getBudgetTier = (val: number) => {
    if (val < 2000) return 'Essential';
    if (val < 10000) return 'Standard';
    if (val < 25000) return 'Premium';
    return 'Luxury';
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;

    setIsGenerating(true);
    try {
      const budgetContext = `The project budget is approximately $${budget.toLocaleString()} (${getBudgetTier(budget)} tier). Ensure the materials, furniture, and finishes reflect this budget level.`;
      const fullPrompt = `${prompt}. ${budgetContext}`;

      const base64Image = await generateDesignImage(fullPrompt, aspectRatio);
      setCurrentImage(base64Image);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: base64Image,
        prompt: prompt,
        mode: 'creation',
        timestamp: Date.now()
      };

      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to generate design. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const downloadImage = () => {
    if (currentImage) {
      const link = document.createElement('a');
      link.href = currentImage;
      link.download = `prhomz-design-${Date.now()}.png`;
      link.click();
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-white">Design Creation</h2>
        <p className="text-brand-300">Visualize your dream space with AI-powered generation.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <form onSubmit={handleGenerate} className="space-y-6 bg-brand-900/50 p-6 rounded-2xl border border-brand-800">
            <div className="space-y-2">
              <label className="text-sm font-medium text-brand-200">Describe your vision</label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="E.g., A minimalist living room with floor-to-ceiling windows overlooking a forest..."
                className="w-full h-32 bg-brand-950 border border-brand-700 rounded-lg p-4 text-white placeholder-brand-600 focus:ring-2 focus:ring-brand-500 focus:border-transparent resize-none"
              />
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-end">
                <label className="text-sm font-medium text-brand-200">Project Budget</label>
                <span className="text-brand-400 text-xs font-mono bg-brand-950 px-2 py-1 rounded border border-brand-800">
                  {getBudgetTier(budget)}
                </span>
              </div>
              <div className="space-y-2">
                <input 
                  type="range" 
                  min="500" 
                  max="50000" 
                  step="500"
                  value={budget}
                  onChange={(e) => setBudget(parseInt(e.target.value))}
                  className="w-full h-1.5 bg-brand-800 rounded-lg appearance-none cursor-pointer accent-brand-500"
                />
                <div className="flex justify-between text-[10px] text-brand-500 font-bold uppercase tracking-wider">
                  <span>$500</span>
                  <span className="text-brand-300 font-mono text-sm">${budget.toLocaleString()}{budget === 50000 ? '+' : ''}</span>
                  <span>$50,000+</span>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-brand-200">Aspect Ratio</label>
              <div className="grid grid-cols-3 gap-2">
                {(['16:9', '1:1', '9:16'] as AspectRatio[]).map((ratio) => (
                  <button
                    key={ratio}
                    type="button"
                    onClick={() => setAspectRatio(ratio)}
                    className={`
                      py-2 px-3 rounded-md text-sm font-medium transition-colors
                      ${aspectRatio === ratio 
                        ? 'bg-brand-700 text-white border border-brand-500' 
                        : 'bg-brand-950 text-brand-400 border border-brand-800 hover:border-brand-600'}
                    `}
                  >
                    {ratio}
                  </button>
                ))}
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full py-3" 
              isLoading={isGenerating}
              disabled={!prompt.trim()}
            >
              <Sparkles className="w-4 h-4 mr-2" />
              Generate Design
            </Button>
          </form>

          <div className="flex flex-wrap gap-2">
            {['Modern Rustic', 'Scandinavian', 'Industrial Loft', 'Japandi', 'Art Deco'].map(tag => (
              <button
                key={tag}
                onClick={() => setPrompt(prev => prev + (prev ? ' ' : '') + tag)}
                className="px-3 py-1 bg-brand-900/30 text-xs text-brand-400 rounded-full border border-brand-800 hover:bg-brand-800 hover:text-brand-200 transition-colors"
              >
                + {tag}
              </button>
            ))}
          </div>
        </div>

        <div className="relative group min-h-[400px] flex items-center justify-center bg-brand-950 rounded-2xl border-2 border-dashed border-brand-800 overflow-hidden">
          {currentImage ? (
            <div className="relative w-full h-full">
              <img 
                src={currentImage} 
                alt="Generated Design" 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center space-y-4">
                 <Button 
                    onClick={() => setIsShopOpen(true)}
                    className="bg-white text-brand-900 hover:bg-brand-100 hover:text-brand-900 border-none shadow-xl transform hover:scale-105 transition-all"
                  >
                    <ShoppingBag className="w-4 h-4 mr-2" />
                    Shop This Look
                  </Button>
                  <Button variant="secondary" onClick={downloadImage}>
                    <Download className="w-4 h-4 mr-2" />
                    Download
                  </Button>
              </div>
            </div>
          ) : (
            <div className="text-center text-brand-600 p-8">
              {isGenerating ? (
                <div className="animate-pulse space-y-4">
                  <div className="w-16 h-16 bg-brand-800 rounded-full mx-auto"></div>
                  <div className="text-sm font-medium">Crafting for ${budget.toLocaleString()} budget...</div>
                </div>
              ) : (
                <>
                  <Sparkles className="w-12 h-12 mx-auto mb-4 opacity-50" />
                  <p>Your design will appear here</p>
                </>
              )}
            </div>
          )}
        </div>
      </div>

      {currentImage && (
        <ShopLookModal 
          image={currentImage} 
          isOpen={isShopOpen} 
          onClose={() => setIsShopOpen(false)} 
        />
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
