  const getBudgetTier = (val: number) => {
    if (val < 1500) return 'Essential';
    if (val < 5000) return 'Standard';
    if (val < 15000) return 'Premium';
    return 'Luxury';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || !instruction.trim()) return;

    setIsProcessing(true);
    try {
      const budgetContext = `The remodel budget is $${budget.toLocaleString()} (${getBudgetTier(budget)} tier). Prioritize changes and additions that fit this cost profile.`;
      const fullInstruction = `${instruction}. ${budgetContext}`;

      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Remodel ($${budget.toLocaleString()}): ${instruction}`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-white">Room Remodeler</h2>
        <p className="text-brand-300">Upload a photo and give instructions to transform it.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        <div className="space-y-6">
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`
              relative h-64 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center cursor-pointer transition-all
              ${previewUrl 
                ? 'border-brand-700 bg-brand-950' 
                : 'border-brand-600 bg-brand-900/30 hover:bg-brand-900/50 hover:border-brand-500'}
            `}
          >
            {previewUrl ? (
              <img src={previewUrl} alt="Original" className="w-full h-full object-contain rounded-xl p-2" />
            ) : (
              <div className="text-center p-6 space-y-2 text-brand-400">
                <Upload className="w-10 h-10 mx-auto mb-2" />
                <p className="font-medium">Click to upload photo</p>
                <p className="text-xs text-brand-500">JPG, PNG up to 5MB</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange}
              accept="image/*"
              className="hidden" 
            />
          </div>

          <form onSubmit={handleRemodel} className="space-y-6 bg-brand-900/50 p-6 rounded-2xl border border-brand-800">
            <div className="space-y-2">
              <label className="text-sm font-medium text-brand-200">What should we change?</label>
              <div className="relative">
                <input
                  type="text"
                  value={instruction}
                  onChange={(e) => setInstruction(e.target.value)}
                  placeholder="E.g., Change the wall color to sage green"
                  className="w-full bg-brand-950 border border-brand-700 rounded-lg py-3 px-4 pr-12 text-white placeholder-brand-600 focus:ring-2 focus:ring-brand-500 focus:outline-none"
                />
                <Paintbrush className="absolute right-4 top-3.5 w-5 h-5 text-brand-500" />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-end">
                <label className="text-sm font-medium text-brand-200">Remodel Budget</label>
                <span className="text-brand-400 text-xs font-mono bg-brand-950 px-2 py-1 rounded border border-brand-800">
                  {getBudgetTier(budget)}
                </span>
              </div>
              <div className="space-y-2">
                <input 
                  type="range" 
                  min="500" 
                  max="50000" 
                  step="500"
                  value={budget}
                  onChange={(e) => setBudget(parseInt(e.target.value))}
                  className="w-full h-1.5 bg-brand-800 rounded-lg appearance-none cursor-pointer accent-brand-500"
                />
                <div className="flex justify-between text-[10px] text-brand-500 font-bold uppercase tracking-wider">
                  <span>$500</span>
                  <span className="text-brand-300 font-mono text-sm">${budget.toLocaleString()}{budget === 50000 ? '+' : ''}</span>
                  <span>$50,000+</span>
                </div>
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full" 
              isLoading={isProcessing}
              disabled={!previewUrl || !instruction.trim()}
            >
              Transform Space
            </Button>
          </form>
        </div>

        <div className="space-y-4">
          <div className="h-64 lg:h-[400px] bg-brand-950 rounded-2xl border border-brand-800 flex items-center justify-center relative overflow-hidden group">
            {resultImage ? (
              <div className="relative w-full h-full">
                 <img src={resultImage} alt="Remodeled" className="w-full h-full object-contain" />
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center space-y-3">
                     <Button 
                        onClick={() => setIsShopOpen(true)}
                        className="bg-white text-brand-900 hover:bg-brand-100 hover:text-brand-900 border-none shadow-xl transform hover:scale-105 transition-all"
                      >
                        <ShoppingBag className="w-4 h-4 mr-2" />
                        Shop This Look
                      </Button>
                      <a 
                        href={resultImage} 
                        download={`prhomz-remodel-${Date.now()}.png`}
                        className="inline-flex items-center px-4 py-2 bg-brand-500 text-white rounded-lg hover:bg-brand-400 transition-colors"
                      >
                        <Download className="w-4 h-4 mr-2" />
                        Save Image
                      </a>
                  </div>
              </div>
            ) : (
              <div className="text-brand-700 text-center p-8">
                {isProcessing ? (
                  <div className="space-y-4 animate-pulse">
                     <div className="w-12 h-12 border-4 border-brand-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                     <p className="text-sm font-medium">Reimagining for ${budget.toLocaleString()}...</p>
                  </div>
                ) : (
                  <>
                    <ArrowRight className="w-12 h-12 mx-auto mb-4 opacity-30" />
                    <p>The transformed result will appear here</p>
                  </>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {resultImage && (
        <ShopLookModal 
          image={resultImage} 
          isOpen={isShopOpen} 
          onClose={() => setIsShopOpen(false)} 
        />
      )}
    </div>
  );
};

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { AspectRatio, ProductItem } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates an image based on a text prompt.
 * Uses gemini-2.5-flash-image for standard generation.
 */
export const generateDesignImage = async (
  prompt: string,
  aspectRatio: AspectRatio = "16:9"
): Promise<string> => {
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
        }
      }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Design generation error:", error);
    throw error;
  }
};

/**
 * Edits an existing image based on instructions.
 */
export const remodelImage = async (
  base64Image: string,
  instruction: string
): Promise<string> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: instruction },
        ],
      },
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("No edited image returned");
  } catch (error) {
    console.error("Remodel error:", error);
    throw error;
  }
};

/**
 * Chat with the AI Architect for advice.
 */
export const chatWithArchitect = async (
  history: { role: 'user' | 'model'; text: string }[],
  newMessage: string
): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction: "You are PRHOMZ, a world-class interior designer and architect. Be concise but helpful.",
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const response = await chat.sendMessage({ message: newMessage });
    return response.text || "I couldn't generate a response at this time.";
  } catch (error) {
    console.error("Chat error:", error);
    return "I apologize, but I'm having trouble connecting right now.";
  }
};

/**
 * Analyzes an image to identify products for shopping.
 */
export const generateProductList = async (base64Image: string): Promise<ProductItem[]> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: "Identify 3 to 5 distinct furniture or decor items in this image. For each, provide a name, 10-word description, integer price (USD), and 3 color options." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              price: { type: Type.NUMBER },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["name", "price", "colors", "description"]
          }
        }
      }
    });

    const items = JSON.parse(response.text || "[]");
    return items.map((item: any, index: number) => ({
      ...item,
      id: item.id || `prod-${Date.now()}-${index}`
    }));
  } catch (error) {
    console.error("Product detection error:", error);
    return [];
  }
};

/**
 * Finds a similar alternative for a product in an image.
 */
export const swapProduct = async (base64Image: string, currentProduct: ProductItem): Promise<ProductItem> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `The user identified a "${currentProduct.name}" (${currentProduct.description}) but wants a similar alternative that fits the same space. Provide ONE new product item with a different design/brand. Output JSON.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            price: { type: Type.NUMBER },
            colors: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "price", "colors", "description"]
        }
      }
    });

    const item = JSON.parse(response.text || "{}");
    return { ...item, id: `swap-${Date.now()}` };
  } catch (error) {
    console.error("Swap error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, RefreshCw, Trash2 } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [checkingOut, setCheckingOut] = useState(false);
  const [success, setSuccess] = useState(false);
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());
  const [purchasedItems, setPurchasedItems] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSuccess(false);
      setCheckingOut(false);
      setSwappingIds(new Set());
      setPurchasedItems(new Set());
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => {
        if (item.colors.length > 0) initialSelections[item.id] = item.colors[0];
      });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleRemove = (productId: string) => {
    setProducts(prev => prev.filter(p => p.id !== productId));
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;

    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
      if (newProduct.colors.length > 0) {
        setSelections(prev => ({ ...prev, [newProduct.id]: newProduct.colors[0] }));
      }
    } catch (error) {
      console.error("Swap failed", error);
    } finally {
      setSwappingIds(prev => {
        const next = new Set(prev);
        next.delete(productId);
        return next;
      });
    }
  };

  const handleBulkCheckout = () => {
    setCheckingOut(true);
    setTimeout(() => {
      setCheckingOut(false);
      setSuccess(true);
    }, 1500);
  };

  const handleSingleCheckout = (itemId: string) => {
    setPurchasedItems(prev => new Set(prev).add(itemId));
  };

  if (!isOpen) return null;

  const totalPrice = products.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-brand-900 w-full max-w-5xl rounded-2xl shadow-2xl border border-brand-700 flex flex-col md:flex-row overflow-hidden max-h-[90vh]">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-20 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors"
        >
          <X size={20} />
        </button>

        {/* Left Side: Image */}
        <div className="w-full md:w-5/12 bg-brand-950 relative hidden md:block">
          <img src={image} alt="Design Reference" className="w-full h-full object-cover opacity-90" />
          <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-brand-950 to-transparent p-8">
            <h3 className="text-2xl font-serif text-white font-bold">Shop the Look</h3>
            <p className="text-brand-300 text-sm mt-1">Curated selection from your masterpiece.</p>
          </div>
        </div>

        {/* Right Side: Products */}
        <div className="w-full md:w-7/12 flex flex-col h-full bg-brand-900">
          <div className="p-6 border-b border-brand-800 md:hidden">
            <h3 className="text-xl font-serif text-white font-bold">Shop the Look</h3>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
            {loading ? (
              <div className="h-64 flex flex-col items-center justify-center text-brand-400 space-y-4">
                <Loader2 className="w-10 h-10 animate-spin text-brand-500" />
                <p>Curating your personal shopping list...</p>
              </div>
            ) : success ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6 animate-in fade-in zoom-in duration-300">
                <div className="w-20 h-20 bg-brand-500/20 text-brand-400 rounded-full flex items-center justify-center">
                  <Check size={40} />
                </div>
                <div>
                  <h3 className="text-2xl font-serif font-bold text-white mb-2">Checkout Complete</h3>
                  <p className="text-brand-300">Your curated pieces are on their way.</p>
                  <p className="text-brand-400 text-sm mt-4 font-mono">Order: PRH-{Math.floor(Math.random() * 1000000)}</p>
                </div>
                <Button onClick={onClose} variant="secondary">Back to Design</Button>
              </div>
            ) : (
              products.map((item) => {
                const isPurchased = purchasedItems.has(item.id);
                const isSwapping = swappingIds.has(item.id);

                return (
                  <div key={item.id} className={`
                    group relative flex gap-4 bg-brand-950/40 p-5 rounded-xl border border-brand-800 transition-all
                    ${isSwapping ? 'opacity-50 blur-[1px]' : 'hover:border-brand-600'}
                  `}>
                    <div className="flex-1 space-y-4">
                      <div className="flex justify-between items-start">
                        <div className="max-w-[70%]">
                           <h4 className="font-serif text-lg font-medium text-white leading-tight">{item.name}</h4>
                           <p className="text-xs text-brand-400 mt-1">{item.description}</p>
                        </div>
                        <div className="text-right">
                          <span className="font-mono text-lg text-brand-100">${item.price}</span>
                          <div className="flex gap-2 mt-2 justify-end">
                            <button 
                              onClick={() => handleSwap(item.id)}
                              disabled={isPurchased || isSwapping}
                              className="p-1.5 text-brand-400 hover:text-brand-200 bg-brand-900 rounded-md transition-colors"
                              title="Swap for Similar"
                            >
                              <RefreshCw size={14} className={isSwapping ? 'animate-spin' : ''} />
                            </button>
                            <button 
                              onClick={() => handleRemove(item.id)}
                              disabled={isPurchased || isSwapping}
                              className="p-1.5 text-brand-400 hover:text-red-400 bg-brand-900 rounded-md transition-colors"
                              title="Remove item"
                            >
                              <Trash2 size={14} />
                            </button>
                          </div>
                        </div>
                      </div>

                      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pt-1">
                        <div className="space-y-2">
                          <div className="flex flex-wrap gap-1.5">
                            {item.colors.map((color) => {
                              const isSelected = selections[item.id] === color;
                              return (
                                <button
                                  key={color}
                                  onClick={() => !isPurchased && handleColorSelect(item.id, color)}
                                  disabled={isPurchased || isSwapping}
                                  className={`
                                    px-2.5 py-1 rounded text-[10px] font-bold uppercase tracking-tighter transition-all border
                                    ${isSelected 
                                      ? 'bg-brand-500 border-brand-500 text-white' 
                                      : 'bg-brand-900 border-brand-800 text-brand-500 hover:border-brand-600'}
                                    ${isPurchased ? 'opacity-30' : ''}
                                  `}
                                >
                                  {color}
                                </button>
                              );
                            })}
                          </div>
                        </div>

                        <Button 
                          variant={isPurchased ? "ghost" : "secondary"}
                          size="sm"
                          onClick={() => handleSingleCheckout(item.id)}
                          disabled={isPurchased || isSwapping}
                          className={isPurchased ? "text-brand-300" : "bg-brand-800/50"}
                        >
                          {isPurchased ? (
                            <><Check className="w-3.5 h-3.5 mr-1.5" /> Ready</>
                          ) : (
                            <><CreditCard className="w-3.5 h-3.5 mr-1.5" /> Buy Item</>
                          )}
                        </Button>
                      </div>
                    </div>
                  </div>
                );
              })
            )}

            {!loading && !success && products.length === 0 && (
              <div className="text-center py-20 text-brand-500 flex flex-col items-center">
                <ShoppingBag className="w-12 h-12 mb-4 opacity-20" />
                <p className="font-serif italic">Your selection is empty.</p>
                <Button variant="ghost" size="sm" onClick={loadProducts} className="mt-4">
                  <RefreshCw className="w-3 h-3 mr-2" /> Reset Identification
                </Button>
              </div>
            )}
          </div>

          {!loading && !success && products.length > 0 && (
            <div className="p-6 bg-brand-950 border-t border-brand-800">
              <div className="flex justify-between items-baseline mb-6">
                <div>
                  <span className="text-brand-500 text-xs font-bold uppercase tracking-[0.2em]">Subtotal</span>
                  <p className="text-brand-300 text-sm">{products.length} Premium Pieces</p>
                </div>
                <span className="text-3xl font-serif font-bold text-white">${totalPrice.toLocaleString()}</span>
              </div>
              <Button 
                onClick={handleBulkCheckout} 
                className="w-full py-4 text-lg shadow-2xl"
                size="lg"
                isLoading={checkingOut}
              >
                {!checkingOut && <ShoppingBag className="mr-3 h-5 w-5" />}
                Checkout Selected Design
              </Button>
              <p className="text-center text-[10px] text-brand-500 mt-4 uppercase tracking-[0.3em] opacity-50">
                PRHOMZ Signature Secure Fulfillment
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

