import { Button } from './Button';

type AdminTab = 'overview' | 'inventory' | 'users';

export const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('overview');
  const [analytics, setAnalytics] = useState<AnalyticsSummary | null>(null);
  const [inventory, setInventory] = useState<ProductItem[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [stats, products, accounts] = await Promise.all([
        fetchSystemAnalytics(),
        fetchShopifyProducts(),
        fetchUserDirectory()
      ]);
      setAnalytics(stats);
      setInventory(products);
      setUsers(accounts);
    } catch (error) {
      console.error("Dashboard failed to load", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const freshProducts = await fetchShopifyProducts();
      await syncToFirestore(freshProducts);
      setInventory(freshProducts);
