import { AppMode, GeneratedImage, UserAccount } from './types';
import { Diamond, User as UserIcon, LogOut, ChevronDown } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.GENERATE);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);

  // Mock authentication state
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  // Initialize with a default user on load
  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      // Default to the first client user for security demonstration
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const switchRole = async (role: 'Client' | 'Admin' | 'Designer') => {
    const users = await fetchUserDirectory();
    const targetUser = users.find(u => u.role === role) || users[0];
    setCurrentUser(targetUser);
    setIsProfileOpen(false);
    // Reset to safe mode if switching away from Admin while in Admin mode
    if (role !== 'Admin' && currentMode === AppMode.ADMIN) {
      setCurrentMode(AppMode.GENERATE);
    }
  };

  const renderContent = () => {
    // Permission guard for Admin mode
    if (currentMode === AppMode.ADMIN && currentUser?.role !== 'Admin') {
      return (
        <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6 animate-fade-in">
          <div className="w-20 h-20 bg-red-500/10 border border-red-500/20 rounded-full flex items-center justify-center">
