import React from 'react';
import { LayoutDashboard, Wand2, MessageSquare, Image as ImageIcon, Menu, X, Diamond, ShieldCheck } from 'lucide-react';
import { AppMode } from '../types';

interface NavigationProps {
  currentMode: AppMode;
  onModeChange: (mode: AppMode) => void;
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
  userRole: 'Client' | 'Designer' | 'Admin';
}

export const Navigation: React.FC<NavigationProps> = ({ currentMode, onModeChange, isOpen, setIsOpen, userRole }) => {
  const navItems = [
    { mode: AppMode.GENERATE, label: 'Design', icon: Wand2, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.REMODEL, label: 'Remodel', icon: LayoutDashboard, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.ASSISTANT, label: 'Architect', icon: MessageSquare, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.GALLERY, label: 'Gallery', icon: ImageIcon, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.ADMIN, label: 'Console', icon: ShieldCheck, roles: ['Admin'] },
  ];

  const visibleItems = navItems.filter(item => item.roles.includes(userRole));

  return (
    <>
      <div className="md:hidden fixed top-6 left-6 z-50">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className="p-4 bg-white/5 backdrop-blur-3xl rounded-full text-white border border-white/10"
        >
          {isOpen ? <X size={20} /> : <Menu size={20} />}
        </button>
      </div>

      <nav className={`
        fixed inset-y-0 left-0 z-40 w-24 md:w-28 bg-brand-950 border-r border-white/5 transition-transform duration-1000 cubic-bezier(0.16, 1, 0.3, 1)
        ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="flex flex-col h-full items-center py-12">
          <div className="mb-16">
            <div className="w-12 h-12 flex items-center justify-center">
              <Diamond size={24} className="text-gold-500 fill-gold-500/10" />
            </div>
          </div>

          <div className="flex-1 flex flex-col items-center space-y-10">
            {visibleItems.map((item) => {
              const isActive = currentMode === item.mode;
              return (
                <button
                  key={item.mode}
                  onClick={() => {
                    onModeChange(item.mode);
                    if (window.innerWidth < 768) setIsOpen(false);
                  }}
                  className={`
                    relative group p-4 transition-all duration-500
                    ${isActive ? 'text-gold-500' : 'text-white/20 hover:text-white/60'}
                  `}
                >
                  <item.icon size={22} strokeWidth={1.5} />
                  <span className={`
                    absolute left-full ml-4 px-3 py-1 bg-gold-500 text-white text-[9px] font-black uppercase tracking-[0.2em] rounded opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-300 whitespace-nowrap z-50
