                  </span>
                  {isActive && <div className="absolute right-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-gold-500 rounded-l-full" />}
                </button>
              );
            })}
          </div>

          <div className="mt-auto">
             <div className="w-8 h-px bg-white/10" />
