import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Generator } from './components/Generator';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { AppMode, GeneratedImage, UserAccount } from './types';
import { Diamond, User as UserIcon, LogOut, ChevronDown, Bell } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.GENERATE);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const switchRole = async (role: 'Client' | 'Admin' | 'Designer') => {
    const users = await fetchUserDirectory();
    const targetUser = users.find(u => u.role === role) || users[0];
    setCurrentUser(targetUser);
    setIsProfileOpen(false);
    if (role !== 'Admin' && currentMode === AppMode.ADMIN) {
      setCurrentMode(AppMode.GENERATE);
    }
  };

  const renderContent = () => {
    if (currentMode === AppMode.ADMIN && currentUser?.role !== 'Admin') {
      return (
        <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-8 animate-fade-up">
          <div className="w-16 h-16 bg-white/5 border border-white/10 rounded-full flex items-center justify-center">
            <LogOut className="text-white/40 w-6 h-6" />
          </div>
          <div className="space-y-4">
            <h3 className="text-4xl font-serif font-light italic">Access Restricted</h3>
            <p className="text-white/40 text-[10px] uppercase tracking-[0.4em]">Atelier Credentials Required</p>
          </div>
          <button 
            onClick={() => setCurrentMode(AppMode.GENERATE)}
            className="text-gold-500 text-[9px] font-black uppercase tracking-[0.4em] hover:text-white transition-all"
          >
            Back to Design
          </button>
        </div>
      );
    }

    switch (currentMode) {
      case AppMode.GENERATE: return <Generator onImageGenerated={handleImageGenerated} />;
      case AppMode.REMODEL: return <Remodeler onImageGenerated={handleImageGenerated} />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: return <Gallery images={generatedImages} />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Generator onImageGenerated={handleImageGenerated} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-950 text-white font-sans">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={setCurrentMode}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
        userRole={currentUser?.role || 'Client'}
      />

      <main className="md:pl-28 min-h-screen transition-all duration-700 ease-in-out">
        <header className="h-24 sticky top-0 z-30 flex items-center justify-between px-10 md:px-16 bg-brand-950/80 backdrop-blur-xl border-b border-white/5">
          <div className="flex items-center space-x-6">
            <h1 className="text-3xl font-serif font-black italic tracking-tighter">PRHOMZ</h1>
          </div>

          <div className="flex items-center space-x-8">
            <div className="hidden lg:flex items-center space-x-8 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">
              <a href="https://prhomz.com" target="_blank" rel="noopener noreferrer" className="hover:text-gold-500 transition-colors">Archive</a>
              <a href="#" className="hover:text-gold-500 transition-colors">Atelier</a>
              <a href="#" className="hover:text-gold-500 transition-colors">Studio</a>
            </div>

            <div className="flex items-center space-x-4">
              <button className="p-2 text-white/20 hover:text-gold-500 transition-colors">
                <Bell size={18} />
              </button>

              <div className="relative">
                <button 
                  onClick={() => setIsProfileOpen(!isProfileOpen)}
                  className="flex items-center space-x-3 bg-white/5 hover:bg-white/10 border border-white/5 px-4 py-2 rounded-full transition-all"
                >
                  <div className="w-6 h-6 rounded-full bg-gold-500 flex items-center justify-center">
                    <UserIcon size={12} className="text-white" />
                  </div>
                  <ChevronDown size={12} className={`text-white/20 transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
                </button>

                {isProfileOpen && (
                  <div className="absolute top-full right-0 mt-4 w-64 bg-brand-950 border border-white/10 rounded-2xl shadow-2xl p-3 z-50 animate-fade-up">
                    <div className="p-4 border-b border-white/5 mb-2">
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gold-500 mb-1">{currentUser?.name}</p>
                      <p className="text-[8px] text-white/40 uppercase tracking-widest">{currentUser?.role} Member</p>
                    </div>
                    <button onClick={() => switchRole('Client')} className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/5 text-[9px] font-bold uppercase tracking-widest text-white/60 hover:text-white">Client Access</button>
                    <button onClick={() => switchRole('Admin')} className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/5 text-[9px] font-bold uppercase tracking-widest text-white/60 hover:text-white">Atelier Admin</button>
                    <button onClick={() => switchRole('Designer')} className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/5 text-[9px] font-bold uppercase tracking-widest text-white/60 hover:text-white">Designer Studio</button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </header>

        <div className="px-10 py-16 md:px-16 md:py-24 max-w-[1600px] mx-auto">
          {renderContent()}
        </div>

        <footer className="py-24 px-16 border-t border-white/5 flex flex-col items-center space-y-8 opacity-40 hover:opacity-100 transition-opacity duration-1000">
          <h2 className="font-serif text-3xl font-black italic tracking-tighter">PRHOMZ</h2>
          <div className="flex items-center space-x-8 text-[9px] font-black uppercase tracking-[0.6em] text-white/40">
             <span>Design</span>
             <span className="w-1 h-1 bg-gold-500 rounded-full"></span>
             <span>Decor</span>
             <span className="w-1 h-1 bg-gold-500 rounded-full"></span>
             <span>Delivered</span>
          </div>
          <p className="text-[8px] uppercase tracking-widest text-white/20">© 2025 PRHOMZ GROUP. GLOBAL CURATION STANDARDS.</p>
        </footer>
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Sparkles, Download, ShoppingBag, Maximize2, Diamond, Command } from 'lucide-react';
import { generateDesignImage } from '../services/geminiService';
import { AspectRatio, GeneratedImage } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface GeneratorProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Generator: React.FC<GeneratorProps> = ({ onImageGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [budget, setBudget] = useState(15000);
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const budgetContext = `Budget: $${budget.toLocaleString()}. Ensure materials and furniture reflect this tier.`;
      const fullPrompt = `${prompt}. ${budgetContext}`;
      const base64Image = await generateDesignImage(fullPrompt, aspectRatio);
      setCurrentImage(base64Image);
      onImageGenerated({
        id: Date.now().toString(),
        url: base64Image,
        prompt: prompt,
        mode: 'creation',
        timestamp: Date.now()
      });
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-24 animate-fade-up">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-20 items-end">
        <div className="lg:col-span-8 space-y-10">
          <div className="space-y-4">
            <div className="flex items-center space-x-3 text-gold-500">
              <Diamond size={14} className="animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-[0.5em]">Design Manifest</span>
            </div>
            <h2 className="text-8xl md:text-[10rem] font-serif font-black italic tracking-tighter editorial-text">
              Refinement <br/>
              <span className="text-gold-500 not-italic">Defined.</span>
            </h2>
          </div>
        </div>
        <div className="lg:col-span-4 flex justify-end pb-8">
          <p className="text-white/30 text-right text-sm font-light leading-relaxed max-w-xs italic">
            PRHOMZ studio leverages generative intelligence to architect your sensory environment.
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
        <div className="lg:col-span-4 space-y-12">
          <form onSubmit={handleGenerate} className="space-y-12">
            <div className="space-y-4">
              <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-[0.4em] text-white/20">
                <label>Vision Brief</label>
                <Command size={12} />
              </div>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="Describe your sanctuary..."
                className="w-full bg-transparent border-b border-white/10 py-6 text-xl font-serif italic text-white placeholder-white/10 focus:border-gold-500 focus:outline-none transition-all resize-none min-h-[120px]"
              />
            </div>

            <div className="space-y-6">
              <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.4em] text-white/20">
                <label>Investment Tier</label>
                <span className="text-gold-500">${budget.toLocaleString()}</span>
              </div>
              <input 
                type="range" 
                min="5000" 
                max="250000" 
                step="5000"
                value={budget}
                onChange={(e) => setBudget(parseInt(e.target.value))}
                className="w-full h-px bg-white/10 appearance-none cursor-pointer"
              />
            </div>

            <div className="space-y-4">
              <label className="text-[10px] font-black uppercase tracking-[0.4em] text-white/20">Canvas</label>
              <div className="flex space-x-6">
                {(['16:9', '1:1', '9:16'] as AspectRatio[]).map((ratio) => (
                  <button
                    key={ratio}
                    type="button"
                    onClick={() => setAspectRatio(ratio)}
                    className={`
                      text-[10px] font-black uppercase tracking-widest transition-all
                      ${aspectRatio === ratio ? 'text-gold-500 nav-item-active' : 'text-white/20 hover:text-white/40'}
                    `}
                  >
                    {ratio}
                  </button>
                ))}
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full h-20 rounded-full text-lg font-serif italic font-bold shadow-2xl hover:scale-[1.02] active:scale-98 transition-all" 
              isLoading={isGenerating}
              disabled={!prompt.trim()}
            >
              <Sparkles className="w-5 h-5 mr-4 text-gold-500" />
              Manifest Design
            </Button>
          </form>
        </div>

        <div className="lg:col-span-8">
          <div className="relative aspect-video rounded-[3rem] overflow-hidden gold-border-glow bg-black group shadow-[0_40px_100px_rgba(0,0,0,0.8)]">
            {currentImage ? (
              <div className="relative w-full h-full animate-fade-up">
                <img src={currentImage} alt="Render" className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all duration-700 flex items-center justify-center space-x-6">
                   <Button 
                      onClick={() => setIsShopOpen(true)}
                      className="bg-white text-brand-950 px-10 h-16 rounded-full font-serif italic font-bold text-lg hover:bg-gold-500 hover:text-white transition-all shadow-2xl"
                    >
                      <ShoppingBag size={20} className="mr-3" />
                      Shop Decor
                    </Button>
                    <button onClick={() => {
                        const link = document.createElement('a');
                        link.href = currentImage;
                        link.download = `PRHOMZ-${Date.now()}.png`;
                        link.click();
                      }}
                      className="p-5 bg-white/10 backdrop-blur-xl rounded-full border border-white/10 text-white hover:bg-white/20 transition-all"
                    >
                      <Download size={20} />
                    </button>
                </div>
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-center p-20">
                {isGenerating ? (
                  <div className="space-y-8 flex flex-col items-center">
                    <div className="w-16 h-16 border-t-2 border-gold-500 rounded-full animate-spin"></div>
                    <p className="font-serif italic text-2xl text-white/40">Synthesizing sensory data...</p>
                  </div>
                ) : (
                  <div className="space-y-6 opacity-20">
                    <Diamond size={60} className="mx-auto" />
                    <p className="font-serif italic text-3xl">Architect your reality.</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {currentImage && (
        <ShopLookModal 
          image={currentImage} 
          isOpen={isShopOpen} 
          onClose={() => setIsShopOpen(false)} 
        />
      )}
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-bold uppercase tracking-[0.2em] transition-all duration-500 focus:outline-none disabled:opacity-30 disabled:cursor-not-allowed";

  const sizes = {
    sm: "px-6 py-3 text-[9px]",
    md: "px-10 py-4 text-[10px]",
    lg: "px-14 py-6 text-[12px]"
  };

  const variants = {
    primary: "bg-gold-500 text-white hover:bg-gold-600 shadow-xl shadow-gold-500/10",
    secondary: "bg-transparent border border-white/10 text-white hover:border-gold-500 hover:text-gold-500",
    ghost: "bg-transparent text-white/40 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className}`}
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center space-x-3">
          <svg className="animate-spin h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="italic font-serif normal-case tracking-normal">Processing...</span>
        </span>
      ) : children}
    </button>
  );
};

