import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-bold uppercase tracking-[0.2em] transition-all duration-300 focus:outline-none disabled:opacity-30 disabled:cursor-not-allowed";

  const sizes = {
    sm: "px-6 py-2.5 text-[9px]",
    md: "px-8 py-3.5 text-[10px]",
    lg: "px-12 py-5 text-[11px]"
  };

  const variants = {
    primary: "bg-gold-500 text-brand-950 hover:bg-gold-600 shadow-lg shadow-gold-500/5 active:scale-[0.98]",
    secondary: "bg-transparent border border-white/10 text-white hover:border-gold-500 hover:text-gold-500 active:scale-[0.98]",
    ghost: "bg-transparent text-brand-700 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className}`}
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center space-x-3">
          <svg className="animate-spin h-3 w-3 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="italic font-serif normal-case tracking-normal">Curating...</span>
        </span>
      ) : children}
    </button>
  );
};

