import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-black uppercase tracking-[0.4em] transition-all duration-500 focus:outline-none disabled:opacity-30 disabled:cursor-not-allowed";

  const sizes = {
    sm: "px-8 py-3 text-[9px]",
    md: "px-10 py-4.5 text-[10px]",
    lg: "px-16 py-6 text-[12px]"
  };

  const variants = {
    primary: "bg-bronze-500 text-obsidian-950 hover:bg-vellum-100 hover:text-obsidian-950 shadow-2xl active:scale-[0.97]",
    secondary: "bg-transparent border border-vellum-100/10 text-vellum-100 hover:border-bronze-500 hover:text-bronze-500 active:scale-[0.97]",
    ghost: "bg-transparent text-vellum-100/30 hover:text-vellum-100"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className}`}
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center space-x-4">
          <svg className="animate-spin h-3 w-3 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="italic font-serif normal-case tracking-normal text-base font-medium">Processing...</span>
        </span>
      ) : children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Generator } from './components/Generator';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { AppMode, GeneratedImage, UserAccount } from './types';
import { Diamond, User as UserIcon, LogOut, ChevronDown, Bell, Search } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.GENERATE);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const switchRole = async (role: 'Client' | 'Admin' | 'Designer') => {
    const users = await fetchUserDirectory();
    const targetUser = users.find(u => u.role === role) || users[0];
    setCurrentUser(targetUser);
    setIsProfileOpen(false);
    if (role !== 'Admin' && currentMode === AppMode.ADMIN) {
      setCurrentMode(AppMode.GENERATE);
    }
  };

  const renderContent = () => {
    if (currentMode === AppMode.ADMIN && currentUser?.role !== 'Admin') {
      return (
        <div className="h-[70vh] flex flex-col items-center justify-center text-center space-y-12 animate-entrance">
          <div className="w-24 h-24 border border-vellum-100/10 flex items-center justify-center">
            <LogOut className="text-vellum-100/20 w-8 h-8" />
