            onClick={() => setCurrentMode(AppMode.GENERATE)}
            className="text-vellum-100 text-[9px] font-black uppercase tracking-[0.4em] hover:text-bronze-500 transition-all border-b border-vellum-100/10 hover:border-bronze-500/50 pb-2"
          >
            Return to Creation
          </button>
        </div>
      );
    }

    switch (currentMode) {
      case AppMode.GENERATE: return <Generator onImageGenerated={handleImageGenerated} />;
      case AppMode.REMODEL: return <Remodeler onImageGenerated={handleImageGenerated} />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: return <Gallery images={generatedImages} />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Generator onImageGenerated={handleImageGenerated} />;
    }
  };

  return (
    <div className="min-h-screen bg-obsidian-950 text-vellum-100 font-sans">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={setCurrentMode}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
