            </div>
          </div>

          <div className="flex items-center space-x-12">
            <nav className="hidden xl:flex items-center space-x-10 text-[9px] font-black uppercase tracking-[0.4em] text-vellum-100/30">
              <a href="#" className="hover:text-bronze-500 transition-colors">Catalog</a>
              <a href="#" className="hover:text-bronze-500 transition-colors">Journal</a>
              <a href="#" className="hover:text-bronze-500 transition-colors">Atelier</a>
            </nav>

            <div className="flex items-center space-x-6">
              <button className="relative p-2 text-vellum-100/40 hover:text-bronze-500 transition-colors">
                <Bell size={18} strokeWidth={1.5} />
