                  </div>
                  <ChevronDown size={12} className={`text-vellum-100/20 transition-transform duration-500 ${isProfileOpen ? 'rotate-180' : ''}`} />
                </button>

                {isProfileOpen && (
                  <div className="absolute top-full right-0 mt-2 w-72 bg-obsidian-900 border border-vellum-100/10 shadow-3xl p-4 z-50 animate-entrance ring-1 ring-bronze-500/10">
