        fixed inset-y-0 left-0 z-40 w-64 bg-brand-950 border-r border-white/5 transition-transform duration-500 md:translate-x-0 md:static
        ${isOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="flex flex-col h-full py-12 px-8">
          <div className="mb-16">
            <h2 className="text-2xl font-serif font-black italic tracking-tighter">PRHOMZ</h2>
          </div>

          <div className="flex-1 space-y-4">
            {visibleItems.map((item) => {
              const isActive = currentMode === item.mode;
              return (
