        </div>
      </nav>

      {isOpen && <div className="fixed inset-0 bg-black/50 z-30 md:hidden" onClick={() => setIsOpen(false)} />}
    </>
  );
};

import React, { useState } from 'react';
import { Sparkles, Download, ShoppingBag, Send } from 'lucide-react';
import { generateDesignImage } from '../services/geminiService';
import { AspectRatio, GeneratedImage } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface GeneratorProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Generator: React.FC<GeneratorProps> = ({ onImageGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const base64Image = await generateDesignImage(prompt, aspectRatio);
      setCurrentImage(base64Image);
      onImageGenerated({
        id: Date.now().toString(),
        url: base64Image,
        prompt: prompt,
        mode: 'creation',
        timestamp: Date.now()
      });
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-16 animate-fade">
      <div className="space-y-4">
        <h2 className="text-4xl md:text-6xl font-serif italic tracking-tight">Design Space</h2>
        <p className="text-neutral-500 text-sm tracking-wide uppercase">Curate your architectural vision through natural language.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-12">
          <form onSubmit={handleGenerate} className="relative">
            <input
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Modern minimalist living room with floor-to-ceiling windows..."
              className="w-full bg-transparent border-b border-white/10 py-8 text-xl md:text-2xl font-serif italic focus:outline-none focus:border-accent transition-all placeholder:text-neutral-800"
            />
            <button 
              type="submit" 
              disabled={!prompt.trim() || isGenerating}
              className="absolute right-0 bottom-8 text-accent disabled:opacity-20 transition-all hover:scale-110"
            >
              <Send size={24} />
            </button>
          </form>

          <div className="flex space-x-8 mt-6">
            {(['16:9', '1:1', '9:16'] as AspectRatio[]).map((ratio) => (
              <button
                key={ratio}
                onClick={() => setAspectRatio(ratio)}
