            </div>

            <Button 
              type="submit" 
              className="w-full py-5 rounded-2xl shadow-2xl hover:scale-[1.02] transition-all" 
              isLoading={isProcessing}
              disabled={!previewUrl || (!instruction.trim() && !selectedStyle)}
