import React from 'react';
import { LayoutDashboard, MessageSquare, Image as ImageIcon, ShieldCheck, Menu, X, Sparkles } from 'lucide-react';
import { AppMode } from '../types';

interface NavigationProps {
  currentMode: AppMode;
  onModeChange: (mode: AppMode) => void;
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
  userRole: 'Client' | 'Designer' | 'Admin';
}

export const Navigation: React.FC<NavigationProps> = ({ currentMode, onModeChange, isOpen, setIsOpen, userRole }) => {
  const navItems = [
    { mode: AppMode.REMODEL, label: 'Remodel', icon: Sparkles, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.ASSISTANT, label: 'Assistant', icon: MessageSquare, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.GALLERY, label: 'Gallery', icon: ImageIcon, roles: ['Client', 'Designer', 'Admin'] },
    { mode: AppMode.ADMIN, label: 'Admin', icon: ShieldCheck, roles: ['Admin'] },
  ];

  const visibleItems = navItems.filter(item => item.roles.includes(userRole));

  return (
    <>
      <div className="md:hidden fixed top-6 left-6 z-50">
        <button onClick={() => setIsOpen(!isOpen)} className="p-3 bg-brand-900 border border-white/10 rounded-xl">
          {isOpen ? <X size={20} /> : <Menu size={20} />}
        </button>
      </div>

      <nav className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-brand-950 border-r border-white/5 transition-transform duration-500 md:translate-x-0 md:static
        ${isOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="flex flex-col h-full py-12 px-8">
          <div className="mb-16">
            <h2 className="text-2xl font-serif font-black italic tracking-tighter text-accent">PRHOMZ</h2>
            <p className="text-[8px] font-bold uppercase tracking-[0.4em] text-neutral-600 mt-2">AI DESIGNER</p>
          </div>

          <div className="flex-1 space-y-4">
            {visibleItems.map((item) => {
              const isActive = currentMode === item.mode;
              return (
                <button
                  key={item.mode}
                  onClick={() => {
                    onModeChange(item.mode);
                    if (window.innerWidth < 768) setIsOpen(false);
                  }}
                  className={`
                    w-full flex items-center space-x-4 py-4 px-4 text-[10px] font-bold uppercase tracking-widest transition-all rounded-2xl
                    ${isActive ? 'bg-accent/10 text-accent border border-accent/20' : 'text-neutral-500 hover:text-white hover:bg-white/5'}
                  `}
                >
                  <item.icon size={18} strokeWidth={isActive ? 2 : 1.5} />
                  <span>{item.label}</span>
                </button>
              );
            })}
          </div>
        </div>
      </nav>

      {isOpen && <div className="fixed inset-0 bg-black/50 z-30 md:hidden" onClick={() => setIsOpen(false)} />}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { AppMode, GeneratedImage, UserAccount } from './types';
import { ChevronDown } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.REMODEL);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const renderContent = () => {
    if (currentMode === AppMode.ADMIN && currentUser?.role !== 'Admin') {
      return (
        <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6 animate-fade">
          <h3 className="text-3xl font-serif italic">Access Restricted</h3>
          <p className="text-neutral-500 text-sm uppercase tracking-widest">Admin credentials required</p>
          <button onClick={() => setCurrentMode(AppMode.REMODEL)} className="text-accent text-[10px] font-bold uppercase tracking-widest hover:underline">Return Home</button>
        </div>
      );
    }

    switch (currentMode) {
      case AppMode.REMODEL: return <Remodeler onImageGenerated={handleImageGenerated} />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: return <Gallery images={generatedImages} />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Remodeler onImageGenerated={handleImageGenerated} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-950 text-white font-sans flex flex-col md:flex-row">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={setCurrentMode}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
        userRole={currentUser?.role || 'Client'}
      />

      <main className="flex-1 min-h-screen flex flex-col">
        <header className="h-20 flex items-center justify-between px-8 md:px-12 border-b border-white/5 bg-brand-950/50 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-4">
            <h1 className="text-xl font-serif font-black italic tracking-tight text-accent">PRHOMZ</h1>
          </div>

          <div className="flex items-center space-x-6">
            <div className="relative">
              <button 
                onClick={() => setIsProfileOpen(!isProfileOpen)}
                className="flex items-center space-x-2 text-neutral-400 hover:text-white transition-all text-[10px] font-bold uppercase tracking-widest"
              >
                <span>{currentUser?.name}</span>
                <ChevronDown size={14} className={`transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
              </button>

              {isProfileOpen && (
                <div className="absolute top-full right-0 mt-2 w-48 bg-brand-900 border border-white/10 p-2 shadow-2xl z-50 animate-fade rounded-xl overflow-hidden">
                  <button onClick={() => setIsProfileOpen(false)} className="w-full text-left px-4 py-3 text-[9px] font-bold uppercase tracking-widest hover:bg-white/5 transition-colors">Profile</button>
                  <button onClick={() => setIsProfileOpen(false)} className="w-full text-left px-4 py-3 text-[9px] font-bold uppercase tracking-widest hover:bg-white/5 transition-colors text-red-400">Sign Out</button>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-8 md:p-12 lg:p-16">
          {renderContent()}
        </div>

        <footer className="py-12 px-12 border-t border-white/5 text-center opacity-30">
          <p className="text-[9px] font-bold uppercase tracking-[0.4em]">© 2025 PRHOMZ AI DESIGNER</p>
        </footer>
      </main>
    </div>
  );
}

export default App;

import React, { useState, useRef } from 'react';
import { Upload, Paintbrush, Download, ArrowRight, ShoppingBag, Box, Sparkles, Plus, Image as ImageIcon } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage, DESIGN_PRESETS } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [instruction, setInstruction] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const getBudgetTier = (val: number) => {
    if (val < 1500) return 'Essential';
    if (val < 5000) return 'Standard';
    if (val < 15000) return 'Premium';
    return 'Luxury';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;

    setIsProcessing(true);
    try {
      const budgetContext = `The remodel budget is $${budget.toLocaleString()} (${getBudgetTier(budget)} tier). Prioritize changes and additions that fit this cost profile.`;
      const styleContext = selectedStyle 
        ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt 
        : '';
      const fullInstruction = `${instruction}. ${styleContext}. ${budgetContext}`.trim();

      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Remodel ($${budget.toLocaleString()}): ${instruction} (${selectedStyle})`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const toggleStyle = (id: string) => {
    setSelectedStyle(prev => prev === id ? '' : id);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-16 pb-20 animate-fade">
      {/* Hero Header */}
      <div className="text-center space-y-6 max-w-3xl mx-auto">
        <h2 className="text-5xl md:text-7xl font-serif font-black italic tracking-tighter text-white leading-tight">
          PRHOMZ <span className="text-accent not-italic">Remodel</span>
        </h2>
        <p className="text-neutral-500 text-lg uppercase tracking-[0.3em] font-medium">
          Professional space transformation powered by AI
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
        {/* Input Control Panel */}
        <div className="lg:col-span-5 space-y-12">

          {/* Step 1: Upload */}
          <div className="space-y-4">
             <div className="flex items-center space-x-3 mb-6">
                <div className="w-8 h-8 rounded-full bg-accent/20 border border-accent/30 flex items-center justify-center text-accent font-serif italic font-bold">1</div>
                <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-accent">Source Reference</h3>
             </div>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-80 border-2 border-dashed rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group
                  ${previewUrl 
                    ? 'border-accent/40 bg-brand-900/40' 
                    : 'border-white/10 bg-brand-900/10 hover:border-accent/30 hover:bg-brand-900/30'}
                `}
              >
                {previewUrl ? (
                  <img src={previewUrl} alt="Original" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                ) : (
                  <div className="text-center p-12 space-y-4">
                    <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto group-hover:scale-110 transition-transform border border-white/5">
                      <Plus className="w-6 h-6 text-accent" />
                    </div>
                    <p className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">Click to upload photo</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept="image/*"
                  className="hidden" 
                />
             </div>
          </div>

          {/* Step 2: Manifesto / Style */}
          <div className="space-y-4">
            <div className="flex items-center space-x-3 mb-6">
                <div className="w-8 h-8 rounded-full bg-accent/20 border border-accent/30 flex items-center justify-center text-accent font-serif italic font-bold">2</div>
                <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-accent">Design Manifesto</h3>
             </div>
            <div className="grid grid-cols-2 gap-3">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  type="button"
                  onClick={() => toggleStyle(style.id)}
                  className={`
                    px-4 py-4 text-[9px] font-bold uppercase tracking-widest border transition-all rounded-2xl text-left flex items-center space-x-3
                    ${selectedStyle === style.id 
                      ? 'bg-accent border-accent text-black shadow-2xl' 
                      : 'bg-brand-900/40 border-white/10 text-neutral-500 hover:border-white/30 hover:text-white'}
                  `}
                >
                  <Box size={14} className={selectedStyle === style.id ? 'text-black' : 'text-accent'} />
                  <span>{style.label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Step 3: Refinement */}
          <div className="space-y-4">
             <div className="flex items-center space-x-3 mb-6">
                <div className="w-8 h-8 rounded-full bg-accent/20 border border-accent/30 flex items-center justify-center text-accent font-serif italic font-bold">3</div>
                <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-accent">Transformation Brief</h3>
             </div>
             <div className="relative">
                <textarea
                  value={instruction}
                  onChange={(e) => setInstruction(e.target.value)}
                  placeholder="Describe the changes... e.g. Add a marble fireplace and custom built-in oak shelving."
                  className="w-full bg-brand-900/40 border border-white/10 rounded-[2rem] py-6 px-8 text-white placeholder-neutral-700 focus:ring-2 focus:ring-accent/30 focus:outline-none min-h-[160px] resize-none text-lg font-serif italic"
                />
             </div>
          </div>

          {/* Step 4: Budget */}
          <div className="space-y-8 bg-brand-900/40 p-10 rounded-[2.5rem] border border-white/5">
              <div className="flex justify-between items-center">
                <div className="space-y-1">
                  <h4 className="text-[10px] font-bold uppercase tracking-[0.2em] text-accent">Allocated Budget</h4>
                  <p className="text-[8px] text-neutral-600 uppercase tracking-widest">Resource distribution limit</p>
                </div>
                <div className="px-4 py-2 bg-accent/10 rounded-full border border-accent/20">
                  <span className="text-accent text-[9px] font-black uppercase tracking-widest">
