import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { AppMode, GeneratedImage, UserAccount } from './types';
import { ChevronDown } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.REMODEL);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const renderContent = () => {
    if (currentMode === AppMode.ADMIN && currentUser?.role !== 'Admin') {
      return (
        <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6 animate-fade">
          <h3 className="text-3xl font-serif italic">Access Restricted</h3>
          <p className="text-neutral-500 text-sm uppercase tracking-widest">Admin credentials required</p>
          <button onClick={() => setCurrentMode(AppMode.REMODEL)} className="text-accent text-[10px] font-bold uppercase tracking-widest hover:underline">Return Home</button>
        </div>
      );
    }

    switch (currentMode) {
      case AppMode.REMODEL: return <Remodeler onImageGenerated={handleImageGenerated} />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: return <Gallery images={generatedImages} />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Remodeler onImageGenerated={handleImageGenerated} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-950 text-white font-sans flex flex-col md:flex-row">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={setCurrentMode}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
        userRole={currentUser?.role || 'Client'}
      />

      <main className="flex-1 min-h-screen flex flex-col">
        <header className="h-20 flex items-center justify-between px-8 md:px-12 border-b border-white/5 bg-brand-950/50 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-4">
            <h1 className="text-xl font-serif font-black italic tracking-tight text-accent uppercase tracking-widest">PRHOMZ</h1>
          </div>

          <div className="flex items-center space-x-6">
            <div className="relative">
              <button 
                onClick={() => setIsProfileOpen(!isProfileOpen)}
                className="flex items-center space-x-2 text-neutral-400 hover:text-white transition-all text-[10px] font-bold uppercase tracking-widest"
              >
                <span>{currentUser?.name}</span>
                <ChevronDown size={14} className={`transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
              </button>

              {isProfileOpen && (
                <div className="absolute top-full right-0 mt-2 w-48 bg-brand-900 border border-white/10 p-2 shadow-2xl z-50 animate-fade rounded-xl overflow-hidden">
                  <button onClick={() => setIsProfileOpen(false)} className="w-full text-left px-4 py-3 text-[9px] font-bold uppercase tracking-widest hover:bg-white/5 transition-colors">Profile</button>
                  <button onClick={() => setIsProfileOpen(false)} className="w-full text-left px-4 py-3 text-[9px] font-bold uppercase tracking-widest hover:bg-white/5 transition-colors text-red-400">Sign Out</button>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-8 md:p-12 lg:p-16">
          {renderContent()}
        </div>

        <footer className="py-12 px-12 border-t border-white/5 text-center opacity-30">
          <p className="text-[9px] font-bold uppercase tracking-[0.4em]">© 2025 PRHOMZ AI DESIGNER • SPACE REIMAGINED</p>
        </footer>
      </main>
    </div>
  );
}

export default App;

