        <p className="text-neutral-500 text-sm md:text-base uppercase tracking-[0.4em] font-medium max-w-2xl mx-auto">
          Evolve your physical space with high-fidelity AI vision and curated sourcing.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 items-start">
        {/* Left: Configuration Steps */}
        <div className="lg:col-span-5 space-y-10">

          {/* Step 1: Source */}
          <div className="space-y-6">
             <div className="flex items-center space-x-4 border-b border-white/5 pb-4">
                <span className="w-8 h-8 rounded-full bg-accent/10 border border-accent/30 flex items-center justify-center text-accent font-serif italic text-sm">1</span>
                <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-accent">Upload Your Space</h3>
             </div>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-72 border-2 border-dashed rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group
                  ${previewUrl 
                    ? 'border-accent/40 bg-brand-900/60' 
                    : 'border-white/10 bg-brand-900/20 hover:border-accent/40 hover:bg-brand-900/40'}
                `}
              >
                {previewUrl ? (
                  <div className="w-full h-full relative">
                    <img src={previewUrl} alt="Original" className="w-full h-full object-cover opacity-80 group-hover:scale-105 transition-transform duration-700" />
