                  <div className="text-center p-12 space-y-4">
                    <div className="w-16 h-16 bg-accent/5 rounded-full flex items-center justify-center mx-auto group-hover:scale-110 transition-transform border border-accent/20">
                      <Upload className="w-6 h-6 text-accent" />
