import React, { useState, useRef } from 'react';
import { Upload, Paintbrush, Download, ArrowRight, ShoppingBag, Box, Sparkles, Plus, Image as ImageIcon, CheckCircle2 } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage, DESIGN_PRESETS } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [instruction, setInstruction] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const getBudgetTier = (val: number) => {
    if (val < 1500) return 'Essential';
    if (val < 5000) return 'Standard';
    if (val < 15000) return 'Premium';
    return 'Luxury';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;

    setIsProcessing(true);
    try {
      const budgetContext = `The remodel budget is $${budget.toLocaleString()} (${getBudgetTier(budget)} tier). Prioritize changes and additions that fit this cost profile.`;
      const styleContext = selectedStyle 
        ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt 
        : '';
      const fullInstruction = `${instruction}. ${styleContext}. ${budgetContext}`.trim();

      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Remodel ($${budget.toLocaleString()}): ${instruction} (${selectedStyle})`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const toggleStyle = (id: string) => {
    setSelectedStyle(prev => prev === id ? '' : id);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-16 pb-20 animate-fade">
      {/* Hero Header */}
      <div className="text-center space-y-4 max-w-4xl mx-auto">
        <h2 className="text-5xl md:text-7xl font-serif font-black italic tracking-tighter text-white leading-tight">
          PRHOMZ <span className="text-accent not-italic">REMODEL</span>
        </h2>
        <p className="text-neutral-500 text-sm md:text-base uppercase tracking-[0.4em] font-medium max-w-2xl mx-auto">
          Evolve your physical space with high-fidelity AI vision and curated sourcing.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 items-start">
        {/* Left: Configuration Steps */}
        <div className="lg:col-span-5 space-y-10">

          {/* Step 1: Source */}
          <div className="space-y-6">
             <div className="flex items-center space-x-4 border-b border-white/5 pb-4">
                <span className="w-8 h-8 rounded-full bg-accent/10 border border-accent/30 flex items-center justify-center text-accent font-serif italic text-sm">1</span>
                <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-accent">Upload Space</h3>
             </div>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-72 border-2 border-dashed rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group
                  ${previewUrl 
                    ? 'border-accent/40 bg-brand-900/60' 
                    : 'border-white/10 bg-brand-900/20 hover:border-accent/40 hover:bg-brand-900/40'}
                `}
              >
                {previewUrl ? (
                  <div className="w-full h-full relative">
                    <img src={previewUrl} alt="Original" className="w-full h-full object-cover opacity-80 group-hover:scale-105 transition-transform duration-700" />
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <p className="text-[10px] font-bold uppercase tracking-widest bg-white text-black px-6 py-2 rounded-full shadow-2xl">Replace Image</p>
                    </div>
                  </div>
                ) : (
                  <div className="text-center p-12 space-y-4">
                    <div className="w-16 h-16 bg-accent/5 rounded-full flex items-center justify-center mx-auto group-hover:scale-110 transition-transform border border-accent/20">
                      <Upload className="w-6 h-6 text-accent" />
                    </div>
                    <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-neutral-500">Tap to select photo</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept="image/*"
                  className="hidden" 
                />
             </div>
          </div>

          {/* Step 2: Manifesto */}
          <div className="space-y-6">
            <div className="flex items-center space-x-4 border-b border-white/5 pb-4">
                <span className="w-8 h-8 rounded-full bg-accent/10 border border-accent/30 flex items-center justify-center text-accent font-serif italic text-sm">2</span>
                <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-accent">Design Direction</h3>
             </div>
            <div className="grid grid-cols-2 gap-3">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  type="button"
                  onClick={() => toggleStyle(style.id)}
                  className={`
                    px-6 py-4 text-[9px] font-bold uppercase tracking-widest border transition-all rounded-2xl text-left flex items-center justify-between
                    ${selectedStyle === style.id 
                      ? 'bg-accent border-accent text-black shadow-2xl scale-[1.02]' 
                      : 'bg-brand-900/40 border-white/10 text-neutral-500 hover:border-white/30 hover:text-white'}
                  `}
                >
                  <span>{style.label}</span>
                  {selectedStyle === style.id && <CheckCircle2 size={14} />}
                </button>
              ))}
            </div>
          </div>

          {/* Step 3: Transformation brief */}
          <div className="space-y-6">
             <div className="flex items-center space-x-4 border-b border-white/5 pb-4">
                <span className="w-8 h-8 rounded-full bg-accent/10 border border-accent/30 flex items-center justify-center text-accent font-serif italic text-sm">3</span>
                <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-accent">Transformation brief</h3>
             </div>
             <div className="relative group">
                <textarea
                  value={instruction}
                  onChange={(e) => setInstruction(e.target.value)}
                  placeholder="Describe your desired updates... e.g. Replace the dark sofa with a minimal ivory linen lounge and add biophilic elements."
                  className="w-full bg-brand-900/60 border border-white/10 rounded-[2rem] py-8 px-10 text-white placeholder-neutral-700 focus:ring-2 focus:ring-accent/30 focus:outline-none min-h-[180px] resize-none text-lg font-serif italic leading-relaxed shadow-inner"
                />
             </div>
          </div>

          {/* Step 4: Investment */}
          <div className="space-y-8 bg-brand-900/60 p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
              <div className="flex justify-between items-center">
                <div className="space-y-1">
                  <h4 className="text-[10px] font-bold uppercase tracking-[0.4em] text-accent">Project Investment</h4>
                  <p className="text-[8px] text-neutral-600 uppercase tracking-widest">Informs asset sourcing</p>
                </div>
                <div className="px-5 py-2 bg-accent/10 rounded-full border border-accent/30">
                  <span className="text-accent text-[10px] font-black uppercase tracking-widest">
                    {getBudgetTier(budget)}
                  </span>
                </div>
              </div>
              <div className="space-y-8">
                <input 
                  type="range" 
                  min="500" 
                  max="50000" 
                  step="500"
                  value={budget}
                  onChange={(e) => setBudget(parseInt(e.target.value))}
                  className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-accent"
                />
