import React, { useState, useRef } from 'react';
import { Upload, Paintbrush, Download, ArrowRight, ShoppingBag, Box, Sparkles, Plus, Image as ImageIcon, CheckCircle2, ChevronRight } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage, DESIGN_PRESETS } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [instruction, setInstruction] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const getBudgetTier = (val: number) => {
    if (val < 1500) return 'Essential';
    if (val < 5000) return 'Standard';
    if (val < 15000) return 'Premium';
    return 'Luxury';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;

    setIsProcessing(true);
    try {
      const budgetContext = `The remodel budget is $${budget.toLocaleString()} (${getBudgetTier(budget)} tier). Prioritize changes and additions that fit this cost profile.`;
      const styleContext = selectedStyle 
        ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt 
        : '';
      const fullInstruction = `${instruction}. ${styleContext}. ${budgetContext}`.trim();

      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: outputBase64,
        prompt: `Remodel ($${budget.toLocaleString()}): ${instruction} (${selectedStyle})`,
        mode: 'edit',
        timestamp: Date.now()
      };
      onImageGenerated(newImage);
    } catch (error) {
      alert("Failed to remodel image. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const toggleStyle = (id: string) => {
    setSelectedStyle(prev => prev === id ? '' : id);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-20 pb-20 animate-fade">
      {/* Hero Header */}
      <div className="text-center space-y-6 max-w-4xl mx-auto">
        <h2 className="text-5xl md:text-8xl font-serif font-black italic tracking-tighter text-brand-950 leading-none">
          REMODEL <span className="text-accent not-italic">ATELIER</span>
        </h2>
        <p className="text-brand-500 text-sm md:text-base uppercase tracking-[0.5em] font-black max-w-2xl mx-auto">
          AI Guided Spatial Transformation
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 items-start">
        {/* Left: Configuration Steps */}
        <div className="lg:col-span-5 space-y-12">

          {/* Step 1: Source */}
          <div className="space-y-6">
             <div className="flex items-center justify-between border-b border-brand-200 pb-4">
                <div className="flex items-center space-x-4">
                   <span className="w-8 h-8 rounded-full bg-brand-100 border border-brand-200 flex items-center justify-center text-accent font-serif italic text-sm font-bold">1</span>
                   <h3 className="text-[11px] font-black uppercase tracking-[0.3em] text-brand-950">Original Concept</h3>
                </div>
                {previewUrl && <CheckCircle2 size={16} className="text-green-600" />}
             </div>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                  relative h-80 border-2 border-dashed rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group
                  ${previewUrl 
                    ? 'border-accent bg-white shadow-xl' 
                    : 'border-brand-200 bg-white/50 hover:border-accent hover:bg-white'}
                `}
              >
                {previewUrl ? (
                  <div className="w-full h-full relative">
                    <img src={previewUrl} alt="Original" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" />
                    <div className="absolute inset-0 bg-white/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <p className="text-[10px] font-black uppercase tracking-widest bg-brand-950 text-white px-8 py-3 rounded-full shadow-2xl">Modify Image</p>
                    </div>
                  </div>
                ) : (
                  <div className="text-center p-12 space-y-4">
                    <div className="w-16 h-16 bg-brand-50 rounded-full flex items-center justify-center mx-auto group-hover:scale-110 transition-transform border border-brand-100">
                      <Plus className="w-6 h-6 text-accent" />
                    </div>
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-500">Tap to upload your space</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept="image/*"
                  className="hidden" 
                />
             </div>
          </div>

          {/* Step 2: Manifesto */}
          <div className="space-y-6">
            <div className="flex items-center space-x-4 border-b border-brand-200 pb-4">
                <span className="w-8 h-8 rounded-full bg-brand-100 border border-brand-200 flex items-center justify-center text-accent font-serif italic text-sm font-bold">2</span>
                <h3 className="text-[11px] font-black uppercase tracking-[0.3em] text-brand-950">Design Manifesto</h3>
             </div>
            <div className="grid grid-cols-2 gap-3">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  type="button"
                  onClick={() => toggleStyle(style.id)}
                  className={`
                    px-6 py-5 text-[9px] font-black uppercase tracking-widest border transition-all rounded-2xl text-left flex items-center justify-between
                    ${selectedStyle === style.id 
                      ? 'bg-accent border-accent text-white shadow-xl scale-[1.02]' 
                      : 'bg-white border-brand-200 text-brand-700 hover:border-accent hover:text-accent'}
                  `}
                >
                  <span>{style.label}</span>
                  {selectedStyle === style.id && <ChevronRight size={14} />}
                </button>
              ))}
            </div>
          </div>

          {/* Step 3: Brief */}
          <div className="space-y-6">
             <div className="flex items-center space-x-4 border-b border-brand-200 pb-4">
                <span className="w-8 h-8 rounded-full bg-brand-100 border border-brand-200 flex items-center justify-center text-accent font-serif italic text-sm font-bold">3</span>
                <h3 className="text-[11px] font-black uppercase tracking-[0.3em] text-brand-950">Strategic Brief</h3>
             </div>
             <div className="relative group">
                <textarea
                  value={instruction}
                  onChange={(e) => setInstruction(e.target.value)}
                  placeholder="Articulate your vision... e.g. Introduce a sculptural travertine fireplace and floor-to-ceiling walnut cabinetry."
                  className="w-full bg-white border border-brand-200 rounded-[2rem] py-8 px-10 text-brand-950 placeholder-brand-200 focus:ring-2 focus:ring-accent/20 focus:border-accent focus:outline-none min-h-[180px] resize-none text-xl font-serif italic leading-relaxed shadow-sm transition-all"
                />
             </div>
          </div>

          {/* Step 4: Investment */}
          <div className="space-y-8 bg-white p-10 rounded-[2.5rem] border border-brand-200 shadow-xl">
              <div className="flex justify-between items-center">
                <div className="space-y-1">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-brand-950">Allocated Investment</h4>
                  <p className="text-[8px] text-brand-500 uppercase tracking-widest font-bold">Influences curation logic</p>
                </div>
                <div className="px-5 py-2 bg-brand-50 rounded-full border border-brand-100">
                  <span className="text-accent text-[10px] font-black uppercase tracking-widest">
                    {getBudgetTier(budget)}
                  </span>
                </div>
              </div>
              <div className="space-y-8">
                <input 
                  type="range" 
                  min="500" 
                  max="50000" 
                  step="500"
                  value={budget}
                  onChange={(e) => setBudget(parseInt(e.target.value))}
                  className="w-full h-1 bg-brand-100 rounded-lg appearance-none cursor-pointer accent-accent"
                />
                <div className="flex justify-between items-end">
                  <span className="text-[10px] text-brand-200 font-bold tracking-widest uppercase">$500</span>
                  <div className="text-center">
                    <span className="text-brand-950 font-serif text-6xl tracking-tighter italic font-black leading-none">${budget.toLocaleString()}</span>
                  </div>
                  <span className="text-[10px] text-brand-200 font-bold tracking-widest uppercase">$50K</span>
                </div>
              </div>
          </div>

          <Button 
            onClick={handleRemodel}
            className="w-full py-10 rounded-[2.5rem] text-2xl font-serif italic shadow-[0_30px_60px_rgba(166,139,103,0.2)] hover:bg-brand-950 hover:text-white transition-all active:scale-[0.98]" 
            isLoading={isProcessing}
            disabled={!previewUrl || (!instruction.trim() && !selectedStyle)}
          >
            Refine Reality
          </Button>
        </div>

        {/* Right: Visualization Canvas */}
        <div className="lg:col-span-7 h-full">
          <div className="sticky top-32">
            <div className={`
              relative group aspect-square lg:aspect-auto lg:h-[82vh] bg-white rounded-[4rem] border border-brand-200 overflow-hidden shadow-[0_60px_100px_rgba(0,0,0,0.05)] flex items-center justify-center
              ${resultImage ? 'cursor-zoom-in' : ''}
            `}>
