import React, { useState, useEffect } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, RefreshCw, Trash2, ArrowUpRight, DollarSign, Package, Diamond, Sparkles, ChevronRight } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [checkingOut, setCheckingOut] = useState(false);
  const [success, setSuccess] = useState(false);
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());
  const [purchasedItems, setPurchasedItems] = useState<Set<string>>(new Set());
  const [workflowStep, setWorkflowStep] = useState<'design' | 'decor' | 'delivered'>('design');

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSuccess(false);
      setCheckingOut(false);
      setSwappingIds(new Set());
      setPurchasedItems(new Set());
      setWorkflowStep('design');
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    setWorkflowStep('design');
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => {
        if (item.colors.length > 0) initialSelections[item.id] = item.colors[0];
      });
      setSelections(initialSelections);
      setWorkflowStep('decor');
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleRemove = (productId: string) => {
    setProducts(prev => prev.filter(p => p.id !== productId));
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;

    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
      if (newProduct.colors.length > 0) {
        setSelections(prev => ({ ...prev, [newProduct.id]: newProduct.colors[0] }));
      }
    } catch (error) {
      console.error("Swap failed", error);
    } finally {
      setSwappingIds(prev => {
        const next = new Set(prev);
        next.delete(productId);
        return next;
      });
    }
  };

  const handleBulkCheckout = () => {
    setCheckingOut(true);
    setTimeout(() => {
      setCheckingOut(false);
      setWorkflowStep('delivered');
      setSuccess(true);
    }, 2000);
  };

  const handleSingleCheckout = (itemId: string) => {
    setPurchasedItems(prev => new Set(prev).add(itemId));
  };

  if (!isOpen) return null;

  const totalPrice = products.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-12 overflow-hidden">
      <div className="absolute inset-0 bg-brand-950/20 backdrop-blur-xl transition-all" onClick={onClose} />

      <div className="relative bg-white w-full max-w-7xl h-[92vh] rounded-[4rem] shadow-[0_80px_160px_rgba(0,0,0,0.15)] border border-brand-200 flex flex-col md:flex-row overflow-hidden animate-fade">
        <button 
          onClick={onClose}
          className="absolute top-10 right-10 z-50 p-5 bg-white border border-brand-200 rounded-full text-brand-950 hover:bg-brand-50 transition-all hover:scale-110 active:scale-95 shadow-xl"
        >
          <X size={22} />
        </button>

        {/* Curation Context Sidebar */}
        <div className="w-full md:w-5/12 bg-brand-50 relative hidden md:flex flex-col border-r border-brand-200">
          <img src={image} alt="Curation Ref" className="absolute inset-0 w-full h-full object-cover opacity-60" />
          <div className="absolute inset-0 bg-gradient-to-t from-white via-white/40 to-transparent" />

          <div className="relative flex-1 p-20 flex flex-col justify-end space-y-10">
            <div className="space-y-4">
              <div className="flex items-center space-x-3 text-accent">
                <Diamond size={20} />
                <span className="text-[12px] font-black uppercase tracking-[0.6em]">Vision Logistics</span>
              </div>
              <h3 className="text-6xl font-serif text-brand-950 font-black leading-none italic tracking-tighter">THE PIECES</h3>
              <p className="text-xl font-serif text-brand-700 font-light italic leading-relaxed">Direct sourcing from our global design network.</p>
            </div>

            <div className="flex items-center space-x-6">
              {[
                { step: 'design', icon: Sparkles, label: 'Design' },
                { step: 'decor', icon: Package, label: 'Curation' },
                { step: 'delivered', icon: ShoppingBag, label: 'Delivery' }
              ].map((item, i) => (
                <React.Fragment key={item.step}>
                  <div className={`flex flex-col items-center space-y-3 transition-all duration-700 ${workflowStep === item.step ? 'scale-110 opacity-100' : 'opacity-20'}`}>
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center border-2 ${workflowStep === item.step ? 'bg-brand-950 border-brand-950 text-white' : 'border-brand-300 text-brand-300'}`}>
