          </div>
        </div>

        {/* Shopping Panel */}
        <div className="w-full md:w-7/12 flex flex-col h-full bg-white">
          <div className="p-16 border-b border-brand-200 flex items-center justify-between bg-white/50 sticky top-0 z-10">
