import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-bold uppercase tracking-[0.2em] transition-all relative overflow-hidden";

  const sizes = {
    sm: "px-6 py-2.5 text-[9px]",
    md: "px-10 py-5 text-[10px]",
    lg: "px-14 py-7 text-[12px]"
  };

  const variants = {
    primary: "bg-accent text-white hover:bg-brand-950 shadow-[0_10px_40px_rgba(166,139,103,0.2)] active:scale-95",
    secondary: "bg-white border border-brand-200 text-brand-950 hover:border-accent hover:text-accent shadow-sm",
    ghost: "bg-transparent text-brand-300 hover:text-brand-950"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className} disabled:opacity-50`}
      disabled={isLoading}
      {...props}
    >
      <span className={isLoading ? "opacity-0" : "opacity-100 flex items-center"}>{children}</span>
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
        </div>
      )}
    </button>
  );
};

