import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Diamond, MoreHorizontal } from 'lucide-react';
import { chatWithDesigner } from '../services/geminiService';
import { ChatMessage } from '../types';

export const Assistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Salutations. I am your PRHOMZ Concierge. How shall we refine your design philosophy or spatial concepts today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => ({ role: m.role, text: m.text }));

    try {
      const responseText = await chatWithDesigner(history, userMsg.text);
      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto h-[calc(100vh-180px)] flex flex-col bg-white rounded-[3rem] border border-brand-200 overflow-hidden shadow-2xl animate-fade">
      {/* Header */}
      <div className="p-10 bg-brand-50 border-b border-brand-200 flex items-center justify-between">
        <div className="flex items-center space-x-6">
          <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center border border-brand-200 shadow-sm">
            <Diamond className="w-7 h-7 text-accent" />
          </div>
          <div>
            <h3 className="font-serif text-3xl font-black text-brand-950 tracking-tight leading-none italic uppercase">PRHOMZ</h3>
            <div className="flex items-center space-x-2 mt-2">
              <span className="w-2 h-2 bg-accent rounded-full animate-pulse shadow-[0_0_8px_rgba(166,139,103,1)]"></span>
              <p className="text-[10px] text-brand-500 font-black uppercase tracking-[0.4em]">Concierge Active</p>
            </div>
          </div>
        </div>
        <button className="p-4 hover:bg-white rounded-full transition-all text-brand-200">
          <MoreHorizontal size={22} />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-12 space-y-10 custom-scrollbar bg-brand-50/20">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`
              max-w-[80%] rounded-3xl p-8 transition-all animate-fade shadow-sm
              ${msg.role === 'user' 
                ? 'bg-brand-950 text-white rounded-br-none shadow-xl' 
                : 'bg-white text-brand-900 border border-brand-200 rounded-bl-none'}
            `}>
              <p className="text-lg leading-relaxed whitespace-pre-wrap font-medium">{msg.text}</p>
              <div className={`text-[9px] mt-4 font-black uppercase tracking-[0.4em] opacity-30 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {msg.role === 'user' ? 'Client' : 'Concierge'}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white rounded-3xl rounded-bl-none p-8 border border-brand-200 flex space-x-2 items-center shadow-sm">
              <div className="w-2 h-2 bg-accent rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
              <div className="w-2 h-2 bg-accent rounded-full animate-bounce" style={{ animationDelay: '200ms' }}></div>
              <div className="w-2 h-2 bg-accent rounded-full animate-bounce" style={{ animationDelay: '400ms' }}></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSend} className="p-10 bg-white border-t border-brand-200">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Discuss aesthetic theories, spatial optimization, or material palettes..."
            className="w-full bg-brand-50 border border-brand-200 text-brand-950 rounded-[2.5rem] py-6 pl-10 pr-20 focus:ring-4 focus:ring-accent/10 focus:border-accent focus:outline-none placeholder-brand-200 transition-all shadow-inner text-lg font-serif italic"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-4 top-3 p-4 bg-accent text-white rounded-full hover:bg-brand-950 disabled:opacity-30 disabled:grayscale transition-all shadow-xl hover:scale-110 active:scale-90"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-center text-[10px] text-brand-200 font-black uppercase tracking-[0.6em] mt-6 opacity-60">
          Inference Engine Active
        </p>
      </form>
    </div>
  );
};

