import React, { useState, useRef } from 'react';
import { Upload, Download, ShoppingBag, Plus, ImageIcon, CheckCircle2, ChevronRight, Wand2 } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage, DESIGN_PRESETS } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [instruction, setInstruction] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async () => {
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;
    setIsProcessing(true);
    try {
      const styleContext = selectedStyle ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt : '';
      const fullInstruction = `${instruction}. ${styleContext}. Budget: $${budget}`.trim();
      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);
      onImageGenerated({
        id: Date.now().toString(),
        url: outputBase64,
        prompt: fullInstruction,
        mode: 'edit',
        timestamp: Date.now()
      });
    } catch (error) {
      alert("Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto animate-fade">
      <header className="mb-12">
        <h2 className="text-3xl font-semibold text-google-dark mb-2">Remodel your space</h2>
        <p className="text-google-gray">Upload a photo and let AI suggest high-fidelity interior changes.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        {/* Input Panel */}
        <div className="lg:col-span-4 space-y-8">
          <section className="bg-white border border-google-border rounded-2xl overflow-hidden p-6 space-y-6">
            <h3 className="text-xs font-bold text-google-gray uppercase tracking-wider">Step 1: Upload Photo</h3>
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`
                relative h-56 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all
                ${previewUrl ? 'border-google-blue bg-google-lightBlue' : 'border-google-border bg-google-surface hover:bg-white'}
              `}
            >
              {previewUrl ? (
                <img src={previewUrl} alt="Preview" className="w-full h-full object-cover rounded-lg" />
              ) : (
                <div className="text-center p-6 space-y-2">
                  <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto shadow-sm">
                    <Plus className="w-5 h-5 text-google-blue" />
                  </div>
                  <p className="text-xs font-medium text-google-gray">Select image file</p>
                </div>
              )}
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            </div>
          </section>

          <section className="bg-white border border-google-border rounded-2xl p-6 space-y-6">
            <h3 className="text-xs font-bold text-google-gray uppercase tracking-wider">Step 2: Define Vision</h3>
            <div className="grid grid-cols-2 gap-2">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSelectedStyle(prev => prev === style.id ? '' : style.id)}
                  className={`
                    px-3 py-2 text-xs font-medium border rounded-lg transition-all text-left
                    ${selectedStyle === style.id ? 'bg-google-blue text-white border-google-blue' : 'bg-white border-google-border text-google-dark hover:bg-google-surface'}
                  `}
                >
                  {style.label}
                </button>
              ))}
            </div>
            <textarea
              value={instruction}
              onChange={(e) => setInstruction(e.target.value)}
              placeholder="E.g. Add a clean oak bookshelf and neutral linen rugs..."
              className="w-full bg-google-surface border border-google-border rounded-xl p-4 text-sm focus:ring-2 focus:ring-google-blue focus:outline-none min-h-[120px] resize-none"
            />
          </section>

          <section className="bg-white border border-google-border rounded-2xl p-6 space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xs font-bold text-google-gray uppercase tracking-wider">Budget Allocation</h3>
              <span className="text-sm font-semibold text-google-dark">${budget.toLocaleString()}</span>
            </div>
            <input 
              type="range" min="500" max="50000" step="500" value={budget}
              onChange={(e) => setBudget(parseInt(e.target.value))}
              className="w-full"
            />
          </section>

          <Button 
            onClick={handleRemodel} 
            isLoading={isProcessing} 
            className="w-full rounded-xl py-4"
            disabled={!previewUrl || (!instruction.trim() && !selectedStyle)}
          >
            <Wand2 className="w-4 h-4 mr-2" />
            Generate Render
          </Button>
        </div>

        {/* Result Area */}
        <div className="lg:col-span-8">
          <div className="bg-google-surface border border-google-border rounded-[2rem] overflow-hidden flex items-center justify-center min-h-[600px] relative group">
            {resultImage ? (
              <div className="w-full h-full relative">
                <img src={resultImage} alt="Remodeled" className="w-full h-full object-cover" />
                <div className="absolute inset-x-0 bottom-0 p-8 bg-gradient-to-t from-black/60 to-transparent flex items-center justify-center space-x-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  <Button onClick={() => setIsShopOpen(true)} className="rounded-full bg-white text-google-dark hover:bg-google-surface border-none px-8">
                    <ShoppingBag className="w-4 h-4 mr-2" />
