export const Assistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Hi, I’m PRHOMZ. I can help you refine your interior style or suggest spatial changes. What’s on your mind?' }
