              <div className="w-1 h-1 bg-google-gray rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
              <div className="w-1 h-1 bg-google-gray rounded-full animate-bounce" style={{ animationDelay: '200ms' }}></div>
              <div className="w-1 h-1 bg-google-gray rounded-full animate-bounce" style={{ animationDelay: '400ms' }}></div>
