      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 flex items-center justify-between px-6 border-b border-google-border bg-google-bg/80 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center flex-1">
            <h1 className="text-xl font-medium tracking-tight text-google-dark mr-8">PRHOMZ</h1>
            <div className="hidden md:flex flex-1 max-w-2xl bg-google-surface rounded-lg px-4 py-2 items-center border border-google-border">
              <Search size={18} className="text-google-gray mr-3" />
              <input 
                type="text" 
                placeholder="Search designs and assets" 
                className="bg-transparent border-none focus:outline-none text-sm w-full text-google-dark placeholder-google-gray"
              />
            </div>
          </div>

          <div className="flex items-center space-x-2 ml-4">
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <HelpCircle size={20} />
            </button>
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <Settings size={20} />
            </button>
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <Grid size={20} />
