import React, { useState, useEffect } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, RefreshCw, Trash2, ArrowUpRight, DollarSign, Package, Diamond, Sparkles, ChevronRight } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [checkingOut, setCheckingOut] = useState(false);
  const [success, setSuccess] = useState(false);
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());
  const [purchasedItems, setPurchasedItems] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSuccess(false);
      setCheckingOut(false);
      setSwappingIds(new Set());
      setPurchasedItems(new Set());
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => { if (item.colors.length > 0) initialSelections[item.id] = item.colors[0]; });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;
    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
      if (newProduct.colors.length > 0) setSelections(prev => ({ ...prev, [newProduct.id]: newProduct.colors[0] }));
    } catch (error) { console.error("Swap failed", error); }
    finally { setSwappingIds(prev => { const next = new Set(prev); next.delete(productId); return next; }); }
  };

  if (!isOpen) return null;

  const totalPrice = products.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 overflow-hidden">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-google-bg w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-google-border flex flex-col md:flex-row overflow-hidden animate-fade">
        <button onClick={onClose} className="absolute top-6 right-6 z-50 p-3 bg-google-surface border border-google-border rounded-full text-google-dark hover:bg-google-border transition-all shadow-lg"><X size={20} /></button>

        <div className="w-full md:w-5/12 bg-google-surface relative hidden md:flex flex-col border-r border-google-border">
          <img src={image} alt="Ref" className="absolute inset-0 w-full h-full object-cover opacity-30 grayscale" />
          <div className="absolute inset-0 bg-gradient-to-t from-google-bg via-google-bg/40 to-transparent" />
          <div className="relative flex-1 p-12 flex flex-col justify-end">
             <h3 className="text-4xl font-bold text-google-dark mb-2">Curation</h3>
             <p className="text-google-gray text-sm leading-relaxed mb-6 font-medium">Sourced specifically for your space using AI Piece Detection.</p>
             <div className="flex space-x-2"><Package className="text-google-blue" size={18} /><span className="text-[10px] uppercase font-black tracking-widest text-google-gray">Authentic Inventory Feed</span></div>
          </div>
        </div>

        <div className="w-full md:w-7/12 flex flex-col h-full bg-google-bg">
          <div className="p-8 border-b border-google-border flex items-center justify-between">
            <h3 className="text-xl font-semibold text-google-dark">Shopping List</h3>
            <span className="text-[10px] font-black uppercase tracking-widest text-google-blue bg-google-blue/10 px-3 py-1 rounded-full">{products.length} Items</span>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center space-y-4">
                <Loader2 className="w-10 h-10 animate-spin text-google-blue" />
                <p className="text-sm font-medium text-google-gray animate-pulse">Analyzing pieces...</p>
              </div>
            ) : success ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-6">
                <div className="w-20 h-20 bg-google-blue text-google-bg rounded-full flex items-center justify-center shadow-lg"><Check size={40} /></div>
                <h3 className="text-2xl font-bold text-google-dark">Order Confirmed</h3>
                <p className="text-google-gray text-sm">Our logistics team will verify these items and reach out for delivery details.</p>
                <Button onClick={onClose} variant="secondary" className="rounded-full px-8 mt-4">Close</Button>
              </div>
            ) : (
              <div className="space-y-6">
                {products.map((item) => (
                  <div key={item.id} className="bg-google-surface p-6 rounded-2xl border border-google-border shadow-sm group transition-all hover:border-google-blue">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h4 className="font-bold text-google-dark text-lg">{item.name}</h4>
                        <p className="text-xs text-google-gray leading-relaxed pr-4">{item.description}</p>
                      </div>
                      <div className="text-right">
                        <span className="text-xl font-bold text-google-blue">${item.price.toLocaleString()}</span>
                        <div className="flex space-x-2 mt-3">
                          <button onClick={() => handleSwap(item.id)} className="p-2 text-google-gray hover:text-google-blue hover:bg-google-bg rounded-lg transition-colors border border-google-border" title="Swap"><RefreshCw size={14} className={swappingIds.has(item.id) ? 'animate-spin' : ''} /></button>
                          <button className="p-2 text-google-gray hover:text-red-400 hover:bg-google-bg rounded-lg transition-colors border border-google-border" title="Remove"><Trash2 size={14} /></button>
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-wrap gap-2 pt-4 border-t border-google-border/50">
                      {item.colors.map(color => (
                        <button key={color} onClick={() => handleColorSelect(item.id, color)} className={`px-3 py-1 text-[10px] font-bold rounded-lg border transition-all ${selections[item.id] === color ? 'bg-google-blue text-google-bg border-google-blue' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark'}`}>
                          {color}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {!loading && !success && (
            <div className="p-8 border-t border-google-border bg-google-surface shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <span className="text-google-gray font-bold text-sm uppercase tracking-widest">Total Valuation</span>
                <span className="text-3xl font-bold text-google-dark">${totalPrice.toLocaleString()}</span>
              </div>
              <Button onClick={() => { setCheckingOut(true); setTimeout(() => { setCheckingOut(false); setSuccess(true); }, 1500); }} className="w-full h-16 rounded-2xl text-lg font-bold shadow-lg" isLoading={checkingOut}>
                <CreditCard className="mr-3 w-5 h-5" /> Reserve for Install
              </Button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-bold transition-all relative overflow-hidden disabled:bg-google-border disabled:text-google-gray";

  const sizes = {
    sm: "px-4 py-2 text-xs",
    md: "px-6 py-3 text-sm",
    lg: "px-10 py-4 text-base"
  };

  const variants = {
    primary: "bg-google-blue text-google-bg hover:brightness-110 shadow-md",
    secondary: "bg-google-surface border border-google-border text-google-dark hover:bg-google-border shadow-sm",
    ghost: "bg-transparent text-google-gray hover:text-google-dark hover:bg-google-surface"
  };

  return (
    <button 
      className={`${baseStyles} ${sizes[size]} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      <span className={isLoading ? "opacity-0" : "opacity-100 flex items-center"}>{children}</span>
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-5 h-5 border-2 border-google-bg/30 border-t-google-bg rounded-full animate-spin"></div>
        </div>
      )}
    </button>
  );
};

