import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { AppMode, GeneratedImage, UserAccount } from './types';
import { ChevronDown, Search, HelpCircle, Settings, Grid } from 'lucide-react';
import { fetchUserDirectory } from './services/dataService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.REMODEL);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);

  useEffect(() => {
    const initUser = async () => {
      const users = await fetchUserDirectory();
      setCurrentUser(users[0]);
    };
    initUser();
  }, []);

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.REMODEL: return <Remodeler onImageGenerated={handleImageGenerated} />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: return <Gallery images={generatedImages} />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Remodeler onImageGenerated={handleImageGenerated} />;
    }
  };

  return (
    <div className="min-h-screen bg-google-bg text-google-dark font-sans flex flex-col md:flex-row">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={setCurrentMode}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
        userRole={currentUser?.role || 'Client'}
      />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 flex items-center justify-between px-6 border-b border-google-border bg-google-bg/80 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center flex-1">
            {/* BRANDING REMOVED FROM HERE AS PER REQUEST */}
            <div className="hidden md:flex flex-1 max-w-2xl bg-google-surface rounded-lg px-4 py-2 items-center border border-google-border">
              <Search size={18} className="text-google-gray mr-3" />
              <input 
                type="text" 
                placeholder="Search designs and assets" 
                className="bg-transparent border-none focus:outline-none text-sm w-full text-google-dark placeholder-google-gray"
              />
            </div>
          </div>

          <div className="flex items-center space-x-2 ml-4">
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <HelpCircle size={20} />
            </button>
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <Settings size={20} />
            </button>
            <button className="p-2 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-full transition-colors">
              <Grid size={20} />
            </button>
            <div className="pl-2 border-l border-google-border ml-2">
              <div className="w-8 h-8 rounded-full bg-google-blue text-google-bg flex items-center justify-center text-sm font-bold overflow-hidden">
                {currentUser?.name ? currentUser.name.charAt(0) : 'U'}
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

export default App;

