      {resultImage && <ShopLookModal image={resultImage} isOpen={isShopOpen} onClose={() => setIsShopOpen(false)} budget={budget} />}
    </div>
  );
};

import React, { useState } from 'react';
import { Sparkles, Download, ShoppingBag, Send, Box, Zap, ShieldAlert } from 'lucide-react';
import { generateDesignImage } from '../services/geminiService';
import { AspectRatio, GeneratedImage, DESIGN_PRESETS } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface GeneratorProps {
  onImageGenerated: (image: GeneratedImage) => void;
}

export const Generator: React.FC<GeneratorProps> = ({ onImageGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [budget, setBudget] = useState(10000); // Default budget for generation
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && !selectedStyle) return;
    setIsGenerating(true);
    try {
      const styleContext = selectedStyle 
        ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt 
        : '';
      const finalPrompt = `${prompt} ${styleContext}`.trim();

      const base64Image = await generateDesignImage(finalPrompt, aspectRatio);
      setCurrentImage(base64Image);
      onImageGenerated({
        id: Date.now().toString(),
        url: base64Image,
        prompt: finalPrompt,
        mode: 'creation',
        timestamp: Date.now()
      });
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleStyle = (id: string) => {
    setSelectedStyle(prev => prev === id ? '' : id);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-16 animate-fade">
      <div className="space-y-4">
        <div className="flex items-center space-x-2 text-google-blue mb-1">
          <ShieldAlert size={14} />
          <span className="text-[10px] font-bold uppercase tracking-[0.2em]">Interior Domain Restricted</span>
        </div>
        <p className="text-neutral-500 text-sm tracking-wide uppercase font-medium">Curate high-fidelity interior visions. Optimized for furniture and room upgrades.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-12 space-y-10">
          <form onSubmit={handleGenerate} className="relative group border-b border-google-border focus-within:border-google-blue transition-colors pb-4">
            <input
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Describe your room vision (e.g., Parisian apartment with velvet sofas)..."
              className="w-full bg-transparent py-4 text-xl md:text-2xl font-serif italic focus:outline-none text-google-dark placeholder:text-neutral-700"
            />
            <button 
              type="submit" 
              disabled={(!prompt.trim() && !selectedStyle) || isGenerating}
              className="absolute right-0 bottom-4 text-google-blue disabled:opacity-20 transition-all hover:scale-110 p-2"
            >
              {isGenerating ? <Box size={24} className="animate-spin" /> : <Send size={24} />}
            </button>
          </form>

          {/* Style Presets and Config */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            <div className="space-y-6">
               <div className="flex items-center space-x-2 text-neutral-500">
                  <Box size={14} />
                  <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Design Manifestos</span>
               </div>
               <div className="flex flex-wrap gap-3">
                  {DESIGN_PRESETS.map((style) => (
                    <button
                      key={style.id}
                      onClick={() => toggleStyle(style.id)}
                      className={`
                        px-6 py-2.5 text-[9px] font-bold uppercase tracking-widest border transition-all rounded-sm
                        ${selectedStyle === style.id 
                          ? 'bg-google-blue border-google-blue text-google-bg shadow-[0_0_20px_rgba(138,180,248,0.2)]' 
                          : 'bg-transparent border-google-border text-neutral-500 hover:border-white/30 hover:text-white'}
                      `}
                    >
                      {style.label}
                    </button>
                  ))}
               </div>
            </div>

            <div className="space-y-8">
               <div className="space-y-4">
                  <div className="flex items-center space-x-2 text-neutral-500">
                    <Zap size={14} />
                    <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Canvas Ratio</span>
                  </div>
                  <div className="flex space-x-8">
                    {(['16:9', '1:1', '9:16'] as AspectRatio[]).map((ratio) => (
                      <button
                        key={ratio}
                        onClick={() => setAspectRatio(ratio)}
                        className={`text-[9px] font-bold uppercase tracking-widest transition-all ${aspectRatio === ratio ? 'text-google-blue border-b border-google-blue pb-1' : 'text-neutral-500 hover:text-white'}`}
                      >
                        {ratio}
                      </button>
                    ))}
                  </div>
               </div>

               <div className="space-y-4">
                  <div className="flex justify-between items-center text-neutral-500">
                    <div className="flex items-center space-x-2">
                      <ShoppingBag size={14} />
                      <span className="text-[10px] font-bold uppercase tracking-[0.3em]">Estimated Budget</span>
                    </div>
                    <span className="text-sm font-bold text-google-blue">${budget.toLocaleString()}</span>
                  </div>
                  <input 
                    type="range" min="1000" max="100000" step="1000" value={budget}
                    onChange={(e) => setBudget(parseInt(e.target.value))}
                    className="w-full accent-google-blue"
                  />
               </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-12">
          <div className="relative aspect-video bg-neutral-900 overflow-hidden border border-google-border flex items-center justify-center rounded-xl shadow-2xl">
            {currentImage ? (
              <div className="w-full h-full group">
                <img src={currentImage} alt="Result" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-6">
                  <Button onClick={() => setIsShopOpen(true)} className="bg-white text-black px-8 py-3 rounded-none font-bold">Shop the Look</Button>
                  <button onClick={() => {
                    const link = document.createElement('a');
                    link.href = currentImage;
                    link.download = 'design.png';
                    link.click();
                  }} className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-none border border-white/20"><Download size={20}/></button>
                </div>
              </div>
            ) : (
              <div className="text-center space-y-4">
                {isGenerating ? (
                  <div className="animate-pulse text-google-blue text-[10px] font-bold uppercase tracking-widest">PRHOMZ AI is Processing Spatial Data...</div>
                ) : (
                  <div className="text-neutral-800 uppercase text-[10px] font-bold tracking-[0.4em]">Awaiting Interior Instruction</div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {currentImage && <ShopLookModal image={currentImage} isOpen={isShopOpen} onClose={() => setIsShopOpen(false)} budget={budget} />}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, RefreshCw, Trash2, Package, Bookmark, AlertCircle, Info } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
  budget?: number;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose, budget }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [isProcessing, setIsProcessing] = useState<'checkout' | 'save' | null>(null);
  const [success, setSuccess] = useState<'checkout' | 'save' | null>(null);
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSuccess(null);
      setIsProcessing(null);
      setSwappingIds(new Set());
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => { if (item.colors.length > 0) initialSelections[item.id] = item.colors[0]; });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  // Greedy filtering: Only show products that fit within the remaining budget
  const filteredProducts = useMemo(() => {
    if (budget === undefined) return products;

    let runningTotal = 0;
    return products.filter(product => {
      if (runningTotal + product.price <= budget) {
        runningTotal += product.price;
        return true;
      }
      return false;
    });
  }, [products, budget]);

  const hiddenCount = products.length - filteredProducts.length;

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return {
          ...p,
          imageUrl: `https://loremflickr.com/300/300/${encodeURIComponent(p.name + " " + color + " furniture")}`
        };
      }
      return p;
    }));
  };

  const handleDelete = (productId: string) => {
    setProducts(prev => prev.filter(p => p.id !== productId));
  };

  const handleAction = (type: 'checkout' | 'save') => {
    setIsProcessing(type);
    setTimeout(() => {
      setIsProcessing(null);
      setSuccess(type);
    }, 1200);
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;
    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
      if (newProduct.colors.length > 0) setSelections(prev => ({ ...prev, [newProduct.id]: newProduct.colors[0] }));
    } catch (error) { 
      console.error("Swap failed", error); 
    } finally { 
      setSwappingIds(prev => { 
        const next = new Set(prev); 
        next.delete(productId); 
        return next; 
      }); 
    }
  };

  if (!isOpen) return null;

  const totalPrice = filteredProducts.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 overflow-hidden">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={onClose} />

      <div className="relative bg-google-bg w-full max-w-5xl h-[90vh] rounded-[1.5rem] shadow-2xl border border-google-border flex flex-col md:flex-row overflow-hidden animate-fade">
        {/* Close Button */}
        <button onClick={onClose} className="absolute top-4 right-4 z-50 p-2 text-google-gray hover:text-google-dark hover:bg-google-surface rounded-full transition-all">
          <X size={24} />
        </button>

        {/* Sidebar */}
        <div className="w-full md:w-80 bg-google-surface relative hidden md:flex flex-col border-r border-google-border p-8 justify-between">
          <div className="space-y-4">
            <h3 className="text-xl font-bold text-google-dark">Curated Selection</h3>
            <p className="text-xs text-google-gray leading-relaxed">
              Our AI selected the best combination of items that fit perfectly within your budget constraints.
            </p>
            {budget !== undefined && (
              <div className="pt-4 border-t border-google-border">
                <span className="text-[10px] font-bold text-google-gray uppercase tracking-widest block mb-1">Your Project Budget</span>
                <span className="text-lg font-bold text-google-blue">${budget.toLocaleString()}</span>
              </div>
            )}
          </div>

          <div className="rounded-xl overflow-hidden border border-google-border aspect-square relative group">
            <img src={image} alt="Reference" className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
               <span className="text-[10px] font-bold text-white uppercase tracking-widest">Master Reference</span>
            </div>
          </div>

          <div className="flex items-center space-x-2 opacity-50">
             <Package size={14} />
             <span className="text-[9px] font-bold uppercase tracking-[0.2em]">PRHOMZ AI DESIGNER FEED</span>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 flex flex-col h-full bg-google-bg overflow-hidden">
          <div className="p-6 border-b border-google-border flex items-center justify-between">
            <div className="flex flex-col">
              <h3 className="text-lg font-bold text-google-dark">Shopping List</h3>
              {hiddenCount > 0 && (
                <span className="text-[10px] text-google-gray font-bold uppercase tracking-tighter mt-0.5">
                  {hiddenCount} items hidden to stay within budget
                </span>
              )}
            </div>
            <span className="text-xs font-bold text-google-blue bg-google-blue/10 px-3 py-1 rounded-full border border-google-blue/20">
              {filteredProducts.length} Items Selected
            </span>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center space-y-4">
                <Loader2 className="w-8 h-8 animate-spin text-google-blue" />
                <p className="text-xs font-bold text-google-gray uppercase tracking-widest animate-pulse">Scanning Inventory...</p>
              </div>
            ) : success ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-6">
                <div className="w-16 h-16 bg-google-blue/20 text-google-blue rounded-full flex items-center justify-center">
                  {success === 'checkout' ? <Check size={32} /> : <Bookmark size={32} />}
                </div>
                <h3 className="text-2xl font-bold text-google-dark">
                  {success === 'checkout' ? 'Request Received' : 'List Saved'}
                </h3>
                <p className="text-google-gray text-sm max-w-xs mx-auto">
                  {success === 'checkout' 
                    ? 'A concierge will reach out within 24 hours to confirm shipping and final customizations.' 
                    : 'Your curation has been added to your Atelier Gallery for later viewing.'}
                </p>
                <Button onClick={onClose} variant="secondary" className="rounded-full px-10">Return to Studio</Button>
              </div>
            ) : filteredProducts.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-6">
                <div className="w-16 h-16 bg-google-surface text-google-gray rounded-full flex items-center justify-center border border-google-border">
                  <AlertCircle size={32} />
                </div>
                <h3 className="text-xl font-bold text-google-dark">Budget Too Low</h3>
                <p className="text-google-gray text-sm max-w-xs mx-auto">
                  The detected items exceed your current budget of ${budget?.toLocaleString()}. Try increasing your budget or remodeling with different style prompts.
                </p>
                <Button onClick={onClose} variant="ghost" className="text-google-blue">Adjust Project Budget</Button>
              </div>
            ) : (
              <div className="space-y-4">
                {filteredProducts.map((item) => (
                  <div key={item.id} className="bg-google-surface p-4 rounded-xl border border-google-border flex flex-col sm:flex-row gap-6 animate-fade hover:border-google-blue/40 transition-colors group">
                    <div className="w-full sm:w-32 h-32 flex-shrink-0 bg-google-bg rounded-lg overflow-hidden border border-google-border relative">
                        <img 
                          src={item.imageUrl || `https://placehold.co/300x300/1e1e1e/8ab4f8?text=${encodeURIComponent(item.name)}`} 
                          alt={item.name} 
                          className="w-full h-full object-cover" 
                          key={item.imageUrl}
                        />
                        {swappingIds.has(item.id) && (
                          <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                            <Loader2 size={16} className="text-google-blue animate-spin" />
                          </div>
                        )}
                    </div>

                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div className="flex justify-between items-start">
                        <div>
                          <h4 className="font-bold text-google-dark text-md leading-tight">{item.name}</h4>
                          <p className="text-[11px] text-google-gray mt-1 leading-relaxed max-w-md">{item.description}</p>
                        </div>
                        <div className="text-right">
                          <span className="text-lg font-bold text-google-blue">${item.price.toLocaleString()}</span>
                        </div>
                      </div>

                      <div className="flex flex-wrap items-center justify-between gap-4 mt-auto pt-4">
                        <div className="flex flex-wrap gap-1.5">
                          {item.colors.map(color => (
                            <button 
                              key={color} 
                              onClick={() => handleColorSelect(item.id, color)} 
                              className={`px-3 py-1 text-[9px] font-bold rounded-full border transition-all ${selections[item.id] === color ? 'bg-google-blue text-google-bg border-google-blue' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark'}`}
                            >
                              {color}
                            </button>
                          ))}
                        </div>

                        <div className="flex space-x-1">
                          <button onClick={() => handleSwap(item.id)} className="p-2 text-google-gray hover:text-google-blue hover:bg-google-blue/10 rounded-lg transition-colors border border-google-border" title="Swap Piece">
                            <RefreshCw size={14} className={swappingIds.has(item.id) ? 'animate-spin' : ''} />
                          </button>
                          <button onClick={() => handleDelete(item.id)} className="p-2 text-google-gray hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-colors border border-google-border" title="Remove Item">
                            <Trash2 size={14} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {!loading && !success && filteredProducts.length > 0 && (
            <div className="p-6 border-t border-google-border bg-google-surface shadow-2xl">
              <div className="flex justify-between items-center mb-6 px-2">
                <div>
                  <span className="font-bold text-[10px] uppercase tracking-widest block text-google-gray">
                    Budget-Optimized Subtotal
                  </span>
                  <span className="text-2xl font-bold text-google-dark">
                    ${totalPrice.toLocaleString()}
                  </span>
                </div>
                <div className="text-right hidden sm:block">
                  <div className="flex items-center space-x-1 text-google-blue mb-1 justify-end">
                    <Info size={12} />
                    <span className="text-[10px] font-bold uppercase tracking-tighter">Guaranteed within limit</span>
                  </div>
                  <span className="text-google-gray text-[10px] font-medium uppercase tracking-tight">Concierge Delivery Included</span>
                </div>
              </div>

              <div className="flex flex-col sm:flex-row gap-3">
                <Button 
                  onClick={() => handleAction('save')} 
                  variant="secondary" 
                  className="flex-1 h-14 rounded-xl text-sm font-bold border-google-border" 
                  isLoading={isProcessing === 'save'}
                  disabled={!!isProcessing}
                >
                  <Bookmark className="mr-2 w-4 h-4" /> Save for Later
                </Button>
                <Button 
                  onClick={() => handleAction('checkout')} 
                  className="flex-[1.5] h-14 rounded-xl text-md font-bold shadow-xl bg-google-blue"
                  isLoading={isProcessing === 'checkout'}
                  disabled={!!isProcessing}
                >
                  <CreditCard className="mr-2 w-5 h-5" /> Checkout Now
                </Button>
              </div>

              <p className="text-center text-[10px] text-google-gray mt-4 font-medium uppercase tracking-tighter opacity-60">
                Secured by PRHOMZ AI DESIGNER Logistics Protocol
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

