  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Sparkles, User, Info } from 'lucide-react';
import { chatWithDesigner } from '../services/geminiService';
import { ChatMessage } from '../types';

export const Assistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Hi, I’m PRHOMZ AI DESIGNER.\n\nI can help you refine your interior style, suggest spatial changes, or help you source specific pieces.\n\nWhat’s on your mind today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      const responseText = await chatWithDesigner(history, userMsg.text);
      setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'model', text: responseText }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * Helper to format text with line breaks and handle **bold** syntax
   */
  const formatMessage = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Skip empty lines between paragraphs for cleaner spacing
      if (!line.trim() && i > 0) return <div key={i} className="h-4" />;

      // Simple regex to find **text** and replace with styled spans
      const parts = line.split(/(\*\*.*?\*\*)/g);
      const formattedLine = parts.map((part, j) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return (
            <span key={j} className="font-extrabold text-google-blue">
              {part.slice(2, -2)}
            </span>
          );
        }
        return part;
      });

      // Handle bullet points
      const isBullet = line.trim().startsWith('- ') || line.trim().startsWith('* ');

      return (
        <p key={i} className={`${isBullet ? 'pl-6 relative' : ''} leading-relaxed text-sm mb-1`}>
          {isBullet && <span className="absolute left-1 text-google-blue">•</span>}
          {formattedLine}
        </p>
      );
    });
  };

  return (
    <div className="max-w-5xl mx-auto h-[calc(100vh-160px)] flex flex-col bg-google-surface border border-google-border rounded-3xl overflow-hidden shadow-2xl animate-fade">
      {/* Header */}
      <div className="px-8 py-5 border-b border-google-border flex items-center justify-between bg-google-bg/50 backdrop-blur-sm">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-google-blue/10 rounded-xl flex items-center justify-center border border-google-blue/20">
            <Sparkles size={22} className="text-google-blue" />
          </div>
          <h3 className="text-lg font-bold text-google-dark">PRHOMZ AI Designer</h3>
        </div>
        <div className="flex items-center space-x-3">
          <span className="text-xs font-bold uppercase tracking-widest text-green-400 bg-green-400/10 px-3 py-1 rounded-full border border-green-400/20">Live Systems</span>
          <button className="text-google-gray hover:text-google-dark p-1.5 transition-colors">
            <Info size={18} />
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-google-bg scroll-smooth custom-scrollbar">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-start max-w-[85%] space-x-4 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : ''}`}>
              <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center text-xs font-bold shadow-lg
                ${msg.role === 'user' ? 'bg-google-dark text-google-bg' : 'bg-google-surface text-google-blue border border-google-border'}
              `}>
                {msg.role === 'user' ? <User size={20}/> : <Sparkles size={20}/>}
              </div>
              <div className={`rounded-2xl px-6 py-4 text-base leading-relaxed
                ${msg.role === 'user' 
                  ? 'bg-google-blue text-google-bg font-medium' 
                  : 'bg-google-surface text-google-dark border border-google-border'}
              `}>
                {formatMessage(msg.text)}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-google-surface rounded-2xl px-6 py-4 flex space-x-2 items-center border border-google-border">
              <div className="w-2 h-2 bg-google-blue/60 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
              <div className="w-2 h-2 bg-google-blue/60 rounded-full animate-bounce" style={{ animationDelay: '200ms' }}></div>
              <div className="w-2 h-2 bg-google-blue/60 rounded-full animate-bounce" style={{ animationDelay: '400ms' }}></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSend} className="p-6 border-t border-google-border bg-google-surface">
        <div className="relative group max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Describe a design dilemma or ask for furnishing advice..."
            className="w-full bg-google-bg border border-google-border text-google-dark rounded-2xl py-5 pl-8 pr-16 focus:ring-2 focus:ring-google-blue focus:outline-none shadow-inner text-base placeholder-google-gray transition-all"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-3 top-2.5 p-3 bg-google-blue text-google-bg rounded-xl hover:brightness-110 transition-all disabled:opacity-30 shadow-lg group-hover:scale-105 active:scale-95"
          >
            <Send size={20} />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { X, ShoppingBag, Check, CreditCard, Loader2, RefreshCw, Trash2, Package, Bookmark, AlertCircle, Info, Eye, EyeOff, ShieldCheck, ExternalLink, Zap } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
  budget?: number;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose, budget }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [isProcessing, setIsProcessing] = useState<'checkout' | 'save' | null>(null);
  const [success, setSuccess] = useState<'checkout' | 'save' | null>(null);
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());
  const [filterByBudget, setFilterByBudget] = useState(false);

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSuccess(null);
      setIsProcessing(null);
      setSwappingIds(new Set());
      setFilterByBudget(false);
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => { if (item.colors.length > 0) initialSelections[item.id] = item.colors[0]; });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  const budgetOptimizedProducts = useMemo(() => {
    if (budget === undefined) return products;
    let runningTotal = 0;
    return products.filter(product => {
      if (runningTotal + product.price <= budget) {
        runningTotal += product.price;
        return true;
      }
      return false;
    });
  }, [products, budget]);

  const visibleProducts = filterByBudget ? budgetOptimizedProducts : products;
  const hiddenCount = products.length - budgetOptimizedProducts.length;

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleBuyNow = (item: ProductItem) => {
    window.open(`https://shopify.com/checkout?item=${item.shopifyId}`, '_blank');
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;
    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
    } catch (error) { 
      console.error("Swap failed", error); 
    } finally { 
      setSwappingIds(prev => { 
        const next = new Set(prev); 
        next.delete(productId); 
        return next; 
      }); 
    }
  };

  if (!isOpen) return null;

  const currentTotal = visibleProducts.reduce((sum, item) => sum + item.price, 0);
  const actualTotal = products.reduce((sum, item) => sum + item.price, 0);
  const isOverBudget = budget !== undefined && actualTotal > budget;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 overflow-hidden">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={onClose} />

      <div className="relative bg-google-bg w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-google-border flex flex-col md:flex-row overflow-hidden animate-fade">
        <button onClick={onClose} className="absolute top-6 right-6 z-50 p-3 text-google-gray hover:text-google-dark hover:bg-google-surface rounded-full transition-all">
          <X size={28} />
        </button>

        <div className="w-full md:w-96 bg-google-surface relative hidden md:flex flex-col border-r border-google-border p-10 justify-between">
          <div className="space-y-6">
            <h3 className="text-2xl font-bold text-google-dark">Real Inventory</h3>
            <p className="text-sm text-google-gray leading-relaxed">
              We've synced the artifacts in this render with our live Shopify catalog. Prices and stock levels are updated in real-time for your specific region.
            </p>
            {budget !== undefined && (
              <div className="pt-6 border-t border-google-border">
                <span className="text-xs font-bold text-google-gray uppercase tracking-widest block mb-2">Budget Threshold</span>
                <span className="text-2xl font-bold text-google-blue">${budget.toLocaleString()}</span>
              </div>
            )}
          </div>

          <div className="rounded-2xl overflow-hidden border border-google-border aspect-square relative group shadow-inner">
            <img src={image} alt="Reference" className="w-full h-full object-cover" />
          </div>

          <div className="flex items-center space-x-3 opacity-60">
             <Package size={18} />
             <span className="text-xs font-bold uppercase tracking-[0.2em]">Live Shopify Sync</span>
          </div>
        </div>

        <div className="flex-1 flex flex-col h-full bg-google-bg overflow-hidden">
          <div className="p-8 border-b border-google-border flex items-center justify-between bg-google-bg/50">
            <div className="flex flex-col">
              <h3 className="text-xl font-bold text-google-dark">Artifact Curation</h3>
              <div className="flex items-center space-x-2 mt-2">
                <div className="flex items-center space-x-2 px-3 py-1 rounded-lg bg-google-lightBlue text-google-blue border border-google-blue/20">
                  <Zap size={14} />
                  <span className="text-xs font-bold uppercase tracking-tight">Verified Premium SKUs</span>
                </div>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center space-y-6">
                <Loader2 className="w-10 h-10 animate-spin text-google-blue" />
                <p className="text-sm font-bold text-google-gray uppercase tracking-widest">Querying Inventory Systems...</p>
              </div>
            ) : visibleProducts.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center opacity-40">
                <ShoppingBag size={64} />
                <p className="text-sm font-bold mt-4 uppercase tracking-widest">No artifacts detected</p>
              </div>
            ) : (
              <div className="space-y-4">
                {visibleProducts.map((item) => (
                  <div key={item.id} className="bg-google-surface p-6 rounded-2xl border border-google-border flex flex-col sm:flex-row gap-8 hover:border-google-blue/40 transition-all group">
                    <div className="w-full sm:w-36 h-36 flex-shrink-0 bg-google-bg rounded-xl overflow-hidden border border-google-border relative shadow-sm">
                        <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
                        {swappingIds.has(item.id) && <div className="absolute inset-0 bg-black/60 flex items-center justify-center"><Loader2 size={20} className="text-google-blue animate-spin" /></div>}
                    </div>

                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div className="flex justify-between items-start">
                        <div>
                          <div className="flex items-center space-x-3 mb-2">
                             <h4 className="font-bold text-google-dark text-lg leading-tight">{item.name}</h4>
                             {item.stockLevel && item.stockLevel > 0 ? (
                               <span className="text-xs px-2 py-0.5 bg-green-400/10 text-green-400 border border-green-400/20 rounded-full font-bold uppercase tracking-widest">In Stock ({item.stockLevel})</span>
                             ) : (
                               <span className="text-xs px-2 py-0.5 bg-red-400/10 text-red-400 border border-red-400/20 rounded-full font-bold uppercase tracking-widest">Special Order</span>
                             )}
                          </div>
                          <p className="text-sm text-google-gray mt-1 line-clamp-2 leading-relaxed">{item.description}</p>
                        </div>
                        <span className="text-xl font-bold text-google-blue ml-4">${item.price.toLocaleString()}</span>
                      </div>

                      <div className="flex items-center justify-between mt-6">
                        <div className="flex gap-2">
                          {item.colors.map(color => (
                            <button key={color} onClick={() => handleColorSelect(item.id, color)} className={`px-3 py-1 text-xs font-bold rounded-lg border transition-all ${selections[item.id] === color ? 'bg-google-blue text-google-bg border-google-blue' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark'}`}>
                              {color}
                            </button>
                          ))}
                        </div>
                        <div className="flex space-x-3">
                          <button onClick={() => handleSwap(item.id)} className="p-2 text-google-gray border border-google-border rounded-xl hover:text-google-blue hover:bg-google-bg transition-all" title="Request Alternative"><RefreshCw size={16} /></button>
                          <button 
                            onClick={() => handleBuyNow(item)} 
                            className="px-6 py-2.5 bg-google-blue text-google-bg rounded-xl text-xs font-bold flex items-center shadow-xl hover:brightness-110 transition-all hover:scale-105 active:scale-95"
                            disabled={!item.shopifyId || item.shopifyId === 'external_referral'}
                          >
                            <ExternalLink size={14} className="mr-2" /> 
                            {item.shopifyId === 'external_referral' ? 'Sourcing Info' : 'Direct Buy'}
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {!loading && visibleProducts.length > 0 && (
            <div className="p-8 border-t border-google-border bg-google-surface">
              <div className="flex justify-between items-center max-w-5xl mx-auto">
                <div>
                  <span className="text-xs font-bold text-google-gray uppercase tracking-widest block mb-1">Curation Subtotal</span>
                  <span className="text-3xl font-black text-google-dark">${currentTotal.toLocaleString()}</span>
                </div>
                <div className="flex space-x-4">
                   <Button variant="secondary" className="rounded-2xl px-8 h-14 text-sm font-bold">Save to Project</Button>
                   <Button className="rounded-2xl px-10 h-14 text-sm font-bold shadow-2xl"><CreditCard size={18} className="mr-3" /> Complete Order</Button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

