import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { AspectRatio, ProductItem } from "../types";
import { findMatchingInventory } from "./dataService";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDesignImage = async (prompt: string, aspectRatio: AspectRatio = "16:9"): Promise<string> => {
  try {
    const industryConstraint = "PHOTOREALISTIC HIGH-END INTERIOR DESIGN AND HOME FURNISHING VISION: ";
    const styleSuffix = ", architectural photography, detailed textures, interior decor focus, avoid people, focus on furniture and room layout.";
    const finalPrompt = `${industryConstraint} ${prompt} ${styleSuffix}`;
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: finalPrompt }] },
      config: { imageConfig: { aspectRatio: aspectRatio } }
    });
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found");
  } catch (error) { console.error(error); throw error; }
};

export const remodelImage = async (base64Image: string, instruction: string): Promise<string> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';
    const redesignConstraint = "INTERIOR REDESIGN & FURNISHING UPGRADE: Modify this room by ";
    const finalInstruction = `${redesignConstraint} ${instruction}. Maintain consistent architectural perspective.`;
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ inlineData: { data: base64Data, mimeType: mimeType } }, { text: finalInstruction }]
      }
    });
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No edited image returned");
  } catch (error) { console.error(error); throw error; }
};

export const chatWithDesigner = async (history: { role: 'user' | 'model'; text: string }[], newMessage: string): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: { systemInstruction: "You are PRHOMZ AI DESIGNER." },
      history: history.map(h => ({ role: h.role, parts: [{ text: h.text }] }))
    });
    const response = await chat.sendMessage({ message: newMessage });
    return response.text || "No response";
  } catch (error) { console.error(error); return "Connection error"; }
};

/**
 * Performs an exhaustive spatial scan of the image to identify all visible products.
 */
export const generateProductList = async (base64Image: string): Promise<ProductItem[]> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: "PERFORM EXHAUSTIVE SPATIAL SCAN: Identify EVERY visible product in this design. Detect all furniture (sofas, tables, chairs), lighting (lamps, pendants), textiles (rugs, cushions), and decor (vases, art). For each item found, provide Name, precise Description, and Est. Luxury Price." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              price: { type: Type.NUMBER },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["name", "price", "colors", "description"]
          }
        }
      }
    });

    const items = JSON.parse(response.text || "[]");

    // Match AI items to Real Inventory to get exact prices and direct purchase URLs
    const productsWithMatches = await Promise.all(items.map(async (item: any, index: number) => {
      const inventoryMatch = await findMatchingInventory(item.name);

      return {
        ...item,
        id: `prod-${Date.now()}-${index}`,
        shopifyId: inventoryMatch.shopifyId,
        productUrl: inventoryMatch.productUrl,
        stockLevel: inventoryMatch.stockLevel,
        price: inventoryMatch.price || item.price, // Favor real source price
        imageUrl: inventoryMatch.imageUrl || ""
      };
    }));

    return productsWithMatches;
  } catch (error) { console.error(error); return []; }
};

export const searchCatalog = async (query: string): Promise<ProductItem[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [{ text: `Suggest 6 high-end furniture items matching: "${query}".` }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              price: { type: Type.NUMBER },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["name", "price", "colors", "description"]
          }
        }
      }
    });
    const items = JSON.parse(response.text || "[]");

    const searchResultsWithMatches = await Promise.all(items.map(async (item: any, index: number) => {
      const inventoryMatch = await findMatchingInventory(item.name);
      return {
        ...item,
        id: `search-${Date.now()}-${index}`,
        shopifyId: inventoryMatch.shopifyId,
        productUrl: inventoryMatch.productUrl,
        imageUrl: inventoryMatch.imageUrl || ""
      };
    }));

    return searchResultsWithMatches;
  } catch (error) { console.error(error); return []; }
};

export const swapProduct = async (base64Image: string, currentProduct: ProductItem): Promise<ProductItem> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: `Suggest an alternative high-end furniture piece for "${currentProduct.name}" that would look good in this scene.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            price: { type: Type.NUMBER },
            colors: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "price", "colors", "description"]
        }
      }
    });
    const item = JSON.parse(response.text || "{}");
    const inventoryMatch = await findMatchingInventory(item.name);

    return { 
      ...item, 
      id: `swap-${Date.now()}`, 
      shopifyId: inventoryMatch.shopifyId,
      productUrl: inventoryMatch.productUrl,
      imageUrl: inventoryMatch.imageUrl || "",
      price: inventoryMatch.price || item.price
    };
  } catch (error) { console.error(error); throw error; }
};

import React, { useState, useEffect, useMemo } from 'react';
import { X, ShoppingBag, Loader2, RefreshCw, Package, ExternalLink, Zap, Bookmark, Scan, ShieldCheck } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';
import { SHOPIFY_STORE_URL } from '../services/dataService';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
  budget?: number;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose, budget }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSwappingIds(new Set());
    }
  }, [isOpen, image]);

  const loadProducts = async () => {
    setLoading(true);
    try {
      const items = await generateProductList(image);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => { if (item.colors.length > 0) initialSelections[item.id] = item.colors[0]; });
      setSelections(initialSelections);
    } catch (error) {
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Curation Logic: Enforce strictly budget-compliant product selection.
   * Only returns a subset of items where the running total is within the user's budget.
   */
  const budgetCompliantProducts = useMemo(() => {
    if (budget === undefined || budget === 0) return products;
    let runningTotal = 0;
    return products.filter(product => {
      if (runningTotal + product.price <= budget) {
        runningTotal += product.price;
        return true;
      }
      return false;
    });
  }, [products, budget]);

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleSourcingAction = (item: ProductItem) => {
    if (item.productUrl) {
      // Direct link to the source product page
      window.open(item.productUrl, '_blank');
    } else if (item.shopifyId && item.shopifyId !== 'external_referral') {
      // Direct add to cart if no URL but ID exists
      window.open(`${SHOPIFY_STORE_URL}/cart/${item.shopifyId}:1`, '_blank');
    } else {
      // Generic search as last resort
      window.open(`${SHOPIFY_STORE_URL}/search?q=${encodeURIComponent(item.name)}`, '_blank');
    }
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;
    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
    } catch (error) { 
      console.error("Swap failed", error); 
    } finally { 
      setSwappingIds(prev => { 
        const next = new Set(prev); 
        next.delete(productId); 
        return next; 
      }); 
    }
  };

  if (!isOpen) return null;

  const currentTotal = budgetCompliantProducts.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 overflow-hidden">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={onClose} />

      <div className="relative bg-google-bg w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-google-border flex flex-col md:flex-row overflow-hidden animate-fade">
        <button onClick={onClose} className="absolute top-6 right-6 z-50 p-3 text-google-gray hover:text-google-dark hover:bg-google-surface rounded-full transition-all">
          <X size={28} />
        </button>

        <div className="w-full md:w-96 bg-google-surface relative hidden md:flex flex-col border-r border-google-border p-10 justify-between">
          <div className="space-y-6">
            <div className="flex items-center space-x-2 text-google-blue">
               <ShieldCheck size={20} />
               <h3 className="text-2xl font-bold uppercase tracking-tight">PRHOMZ SYNC</h3>
            </div>
            <p className="text-sm text-google-gray leading-relaxed">
              Every artifact detected in this vision is matched against the live PRHOMZ catalog. 
              <br/><br/>
              <b>Budget Matching:</b> We've curated this selection specifically to fit within your <b>${budget?.toLocaleString()}</b> threshold using live source pricing.
            </p>
            {budget !== undefined && (
              <div className="pt-6 border-t border-google-border">
                <span className="text-xs font-bold text-google-gray uppercase tracking-widest block mb-2">Customer Budget</span>
                <span className="text-2xl font-bold text-google-blue">${budget.toLocaleString()}</span>
              </div>
            )}
          </div>

          <div className="rounded-2xl overflow-hidden border border-google-border aspect-square relative group shadow-inner">
            <img src={image} alt="Reference" className="w-full h-full object-cover" />
            {loading && (
               <div className="absolute inset-0 bg-google-blue/20 backdrop-blur-sm flex flex-col items-center justify-center text-google-blue">
                  <Scan size={48} className="animate-pulse mb-4" />
                  <span className="text-xs font-black uppercase tracking-[0.2em]">Detecting Artifacts...</span>
               </div>
            )}
          </div>

          <div className="flex items-center space-x-3 opacity-60">
             <Package size={18} />
             <span className="text-xs font-bold uppercase tracking-[0.2em]">PRHOMZ LIVE SYNC</span>
          </div>
        </div>

        <div className="flex-1 flex flex-col h-full bg-google-bg overflow-hidden">
          <div className="p-8 border-b border-google-border flex items-center justify-between bg-google-bg/50">
            <div className="flex flex-col">
              <h3 className="text-xl font-bold text-google-dark">Exhaustive Design Curation</h3>
              <div className="flex items-center space-x-2 mt-2">
                <div className="flex items-center space-x-2 px-3 py-1 rounded-lg bg-google-lightBlue text-google-blue border border-google-blue/20">
                  <Zap size={14} />
                  <span className="text-xs font-bold uppercase tracking-tight">Price Verified</span>
                </div>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center space-y-6">
                <div className="relative">
                  <Loader2 className="w-12 h-12 animate-spin text-google-blue" />
                  <Scan className="w-6 h-6 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-google-blue" />
                </div>
                <div className="text-center">
                  <p className="text-sm font-bold text-google-dark uppercase tracking-widest mb-2">Spatial Intelligence Scan</p>
                  <p className="text-xs text-google-gray font-medium">Extracting product signatures and matching PRHOMZ inventory...</p>
                </div>
              </div>
            ) : budgetCompliantProducts.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center opacity-40">
                <ShoppingBag size={64} />
                <p className="text-sm font-bold mt-4 uppercase tracking-widest">No budget-locked matches</p>
                <p className="text-xs mt-2">Try adjusting your project budget for more options.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {budgetCompliantProducts.map((item) => (
                  <div key={item.id} className="bg-google-surface p-6 rounded-2xl border border-google-border flex flex-col hover:border-google-blue/40 transition-all group">
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div className="flex justify-between items-start">
                        <div>
                          <div className="flex items-center space-x-3 mb-2">
                             {swappingIds.has(item.id) ? (
                               <Loader2 size={16} className="text-google-blue animate-spin" />
                             ) : (
                               <Package size={16} className="text-google-blue opacity-50" />
                             )}
                             <h4 className="font-bold text-google-dark text-lg leading-tight">{item.name}</h4>
                             {item.stockLevel && item.stockLevel > 0 ? (
                               <span className="text-xs px-2 py-0.5 bg-green-400/10 text-green-400 border border-green-400/20 rounded-full font-bold uppercase tracking-widest">Available</span>
                             ) : (
                               <span className="text-xs px-2 py-0.5 bg-red-400/10 text-red-400 border border-red-400/20 rounded-full font-bold uppercase tracking-widest">Signature Build</span>
                             )}
                          </div>
                          <p className="text-sm text-google-gray mt-1 line-clamp-2 leading-relaxed">{item.description}</p>
                        </div>
                        <span className="text-xl font-bold text-google-blue ml-4">${item.price.toLocaleString()}</span>
                      </div>

                      <div className="flex items-center justify-between mt-6">
                        <div className="flex gap-2">
                          {item.colors.map(color => (
                            <button key={color} onClick={() => handleColorSelect(item.id, color)} className={`px-3 py-1 text-xs font-bold rounded-lg border transition-all ${selections[item.id] === color ? 'bg-google-blue text-google-bg border-google-blue' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark'}`}>
                              {color}
                            </button>
                          ))}
                        </div>
                        <div className="flex space-x-3">
                          <button onClick={() => handleSwap(item.id)} className="p-2 text-google-gray border border-google-border rounded-xl hover:text-google-blue hover:bg-google-bg transition-all" title="Request Alternative"><RefreshCw size={16} /></button>
                          <button 
                            onClick={() => handleSourcingAction(item)} 
                            className="px-6 py-2.5 bg-google-blue text-google-bg rounded-xl text-xs font-bold flex items-center shadow-xl hover:brightness-110 transition-all hover:scale-105 active:scale-95"
                          >
                            <ExternalLink size={14} className="mr-2" /> 
                            Buy Now
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {!loading && budgetCompliantProducts.length > 0 && (
            <div className="p-8 border-t border-google-border bg-google-surface">
              <div className="flex justify-between items-center max-w-5xl mx-auto">
                <div>
                  <div className="flex items-center space-x-2 mb-1">
                    <span className="text-xs font-bold text-google-gray uppercase tracking-widest">Curation Total</span>
                    {budget && currentTotal <= budget && (
                       <div className="flex items-center space-x-1 px-2 py-0.5 bg-green-400/10 text-green-400 rounded-md border border-green-400/10">
                          <Zap size={10} />
                          <span className="text-[10px] font-black uppercase">Budget Verified</span>
                       </div>
                    )}
                  </div>
                  <span className="text-3xl font-black text-google-dark">${currentTotal.toLocaleString()}</span>
                </div>
                <div className="flex items-center space-x-4">
                   <p className="text-xs text-google-gray font-medium max-w-[240px] text-right hidden sm:block">
                     Individual items are purchased directly through PRHOMZ.
                   </p>
                   <Button variant="secondary" className="rounded-2xl px-8 h-14 text-sm font-bold flex items-center">
                     <Bookmark size={18} className="mr-2" />
                     Save Selection
                   </Button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

