      colors: p.options.find((o: any) => o.name.toLowerCase().includes('color'))?.values || [],
      imageUrl: p.image?.src || (p.images && p.images[0]?.src) || "",
      stockLevel: p.variants[0]?.inventory_quantity || 0,
      lastSynced: Date.now()
    }));

    cachedInventory = products;
    return products;
  } catch (error) {
    console.error("Shopify fetch failed:", error);
    return [];
  }
};

/**
 * Matches AI-detected items against live Shopify inventory.
 * Guarantees that if a match is found, the price and URL are accurate to the source.
 */
export const findMatchingInventory = async (aiDetectedName: string): Promise<Partial<ProductItem>> => {
  if (!cachedInventory) {
    await fetchShopifyProducts();
  }

  const inventory = cachedInventory || [];
  const normalizedSearch = aiDetectedName.toLowerCase();

  // 1. Try to find an exact or very close match
  let match = inventory.find(item => 
    item.name.toLowerCase() === normalizedSearch ||
    item.name.toLowerCase().includes(normalizedSearch) ||
    normalizedSearch.includes(item.name.toLowerCase())
  );

  // 2. If no direct match, try matching by words (keyword match)
  if (!match) {
    const searchWords = normalizedSearch.split(' ').filter(w => w.length > 3);
    match = inventory.find(item => {
      const itemWords = item.name.toLowerCase().split(' ');
      return searchWords.some(sw => itemWords.includes(sw));
    });
  }

  if (match) {
    return {
      name: match.name,
      price: match.price,
      productUrl: match.productUrl,
      shopifyId: match.shopifyId,
      stockLevel: match.stockLevel,
      imageUrl: match.imageUrl
    };
  }

  // Fallback: Use search but explicitly fetch a price if inventory isn't empty to maintain budget logic
  const defaultPrice = inventory.length > 0 ? inventory[0].price : 0;

  return {
    name: aiDetectedName,
    shopifyId: "external_referral",
    productUrl: `${SHOPIFY_STORE_URL}/search?q=${encodeURIComponent(aiDetectedName)}`,
    price: defaultPrice, // Fallback to a real price from store if possible
    stockLevel: 0
  };
};

