/**
 * Performs an exhaustive spatial scan of the image to identify every product.
 * Synchronizes results with the real-time PRHOMZ inventory to guarantee price accuracy.
 */
export const generateProductList = async (base64Image: string): Promise<ProductItem[]> => {
  try {
    const base64Data = base64Image.split(',')[1] || base64Image;
    const mimeType = base64Image.substring(base64Image.indexOf(':') + 1, base64Image.indexOf(';')) || 'image/jpeg';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } },
          { text: "PERFORM DEEP SPATIAL SCAN: Extract every visible piece of furniture and decor. Provide the Name, detailed Description, and estimate price. Focus on high-value items." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              price: { type: Type.NUMBER },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["name", "price", "colors", "description"]
          }
        }
      }
    });

    const items = JSON.parse(response.text || "[]");

    // STRICT SOURCE SYNC: Overwrite all AI data with actual catalog matches
    const productsWithMatches = await Promise.all(items.map(async (item: any, index: number) => {
      const inventoryMatch = await findMatchingInventory(item.name);

      return {
        ...item,
        id: `prod-${Date.now()}-${index}`,
        shopifyId: inventoryMatch.shopifyId,
        productUrl: inventoryMatch.productUrl,
        stockLevel: inventoryMatch.stockLevel,
        // ABSOLUTE PRIORITY: Use inventoryMatch price if it exists, otherwise the AI estimate.
        price: inventoryMatch.price !== undefined && inventoryMatch.price > 0 ? inventoryMatch.price : item.price,
        imageUrl: inventoryMatch.imageUrl || "",
        name: inventoryMatch.name || item.name // Use actual catalog name for better UX
      };
    }));

    return productsWithMatches;
  } catch (error) { console.error(error); return []; }
};

