import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Remodeler } from './components/Remodeler';
import { Assistant } from './components/Assistant';
import { Gallery } from './components/Gallery';
import { AdminDashboard } from './components/AdminDashboard';
import { Auth } from './components/Auth';
import { AppMode, GeneratedImage, UserAccount, ProductItem } from './types';
import { ChevronDown, Search, HelpCircle, Settings, Grid, X, Loader2, ShoppingCart, LogOut } from 'lucide-react';
import { fetchShopifyProducts } from './services/dataService';
import { searchCatalog } from './services/geminiService';

function App() {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.REMODEL);
  const [isNavOpen, setIsNavOpen] = useState(false);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeEditImage, setActiveEditImage] = useState<string | null>(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [searchResults, setSearchResults] = useState<ProductItem[] | null>(null);

  useEffect(() => {
    const storedUser = localStorage.getItem('prhomz_user');
    if (storedUser) {
      setCurrentUser(JSON.parse(storedUser));
    }
    const storedImages = localStorage.getItem('prhomz_gallery');
    if (storedImages) {
      setGeneratedImages(JSON.parse(storedImages));
    }
  }, []);

  useEffect(() => {
    if (generatedImages.length > 0) {
      localStorage.setItem('prhomz_gallery', JSON.stringify(generatedImages));
    }
  }, [generatedImages]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setCurrentMode(AppMode.REMODEL);
  };

  const handleLogout = () => {
    localStorage.removeItem('prhomz_user');
    setCurrentUser(null);
    setGeneratedImages([]);
    setIsProfileOpen(false);
  };

  const handleImageGenerated = (image: GeneratedImage) => {
    setGeneratedImages(prev => [...prev, image]);

    if (currentUser) {
      const now = Date.now();
      const updatedUser: UserAccount = {
        ...currentUser,
        totalRenders: (currentUser.totalRenders || 0) + 1,
        renderTimestamps: [...(currentUser.renderTimestamps || []), now]
      };
      setCurrentUser(updatedUser);
      localStorage.setItem('prhomz_user', JSON.stringify(updatedUser));
    }
  };

  const handleSaveProductsToImage = (imageUrl: string, products: ProductItem[]) => {
    setGeneratedImages(prev => prev.map(img => 
      img.url === imageUrl ? { ...img, savedProducts: products } : img
    ));
  };

  const handleEditFromGallery = (imageUrl: string) => {
    setActiveEditImage(imageUrl);
    setCurrentMode(AppMode.REMODEL);
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsSearching(true);
    try {
      const results = await searchCatalog(searchQuery);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const clearSearch = () => {
    setSearchQuery('');
    setSearchResults(null);
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.REMODEL: 
        return <Remodeler 
          onImageGenerated={handleImageGenerated} 
          initialImage={activeEditImage} 
          onClearInitial={() => setActiveEditImage(null)}
          currentUser={currentUser}
          onSaveProducts={handleSaveProductsToImage}
        />;
      case AppMode.ASSISTANT: return <Assistant />;
      case AppMode.GALLERY: 
        return <Gallery 
          images={generatedImages} 
          onEdit={handleEditFromGallery}
        />;
      case AppMode.ADMIN: return <AdminDashboard />;
      default: return <Remodeler onImageGenerated={handleImageGenerated} currentUser={currentUser} onSaveProducts={handleSaveProductsToImage} />;
    }
  };

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-google-bg text-google-dark font-sans flex flex-col md:flex-row">
      <Navigation 
        currentMode={currentMode} 
        onModeChange={(mode) => {
          setCurrentMode(mode);
          if (mode === AppMode.REMODEL) setActiveEditImage(null);
        }}
        isOpen={isNavOpen}
        setIsOpen={setIsNavOpen}
        userRole={currentUser?.role || 'Client'}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 flex items-center justify-between px-6 md:px-10 border-b border-google-border bg-google-bg/95 backdrop-blur-xl sticky top-0 z-30">
          <div className="flex items-center flex-1">
            <div className="md:hidden flex flex-col ml-12">
               <h1 className="text-lg font-serif italic tracking-tighter text-google-dark leading-none">
                 PRHOMZ <span className="text-google-blue not-italic font-sans font-black">AI</span>
               </h1>
            </div>

            <form onSubmit={handleSearch} className="hidden md:flex flex-1 max-w-xl bg-google-surface rounded-2xl px-5 py-2.5 items-center border border-google-border shadow-inner focus-within:border-google-blue/50 transition-all relative">
              <Search size={16} className="text-google-gray mr-4" />
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search PRHOMZ Catalog for furniture..." 
                className="bg-transparent border-none focus:outline-none text-sm w-full text-google-dark placeholder-google-gray font-medium"
              />
              {isSearching && <Loader2 size={16} className="animate-spin text-google-blue absolute right-4" />}
              {!isSearching && searchQuery && (
                <button type="button" onClick={clearSearch} className="text-google-gray hover:text-google-dark absolute right-4">
                  <X size={16} />
                </button>
              )}
            </form>
          </div>

          <div className="flex items-center space-x-3 ml-4">
            <div className="hidden lg:flex items-center space-x-1 mr-4">
               <button className="p-2.5 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-xl transition-all">
                 <HelpCircle size={18} />
               </button>
               <button className="p-2.5 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-xl transition-all">
                 <Settings size={18} />
               </button>
               <button className="p-2.5 text-google-gray hover:bg-google-surface hover:text-google-dark rounded-xl transition-all">
                 <Grid size={18} />
               </button>
            </div>

            <div className="relative pl-6 border-l border-google-border flex items-center space-x-3 group cursor-pointer" onClick={() => setIsProfileOpen(!isProfileOpen)}>
              <div className="flex flex-col text-right hidden sm:block">
                 <span className="text-[10px] font-bold text-google-dark uppercase tracking-wider">{currentUser?.name || 'Guest User'}</span>
              </div>
              <div className="w-10 h-10 rounded-2xl bg-google-blue text-google-bg flex items-center justify-center text-sm font-black shadow-lg shadow-google-blue/20 transition-transform group-hover:scale-105">
                {currentUser?.name ? currentUser.name.charAt(0).toUpperCase() : 'U'}
              </div>

              {isProfileOpen && (
                <div className="absolute right-0 top-full mt-2 w-48 bg-google-surface border border-google-border rounded-2xl shadow-2xl p-2 animate-in fade-in zoom-in-95 duration-200">
                  <div className="px-4 py-3 border-b border-google-border mb-1">
                    <p className="text-[10px] font-bold text-google-gray uppercase tracking-widest">{currentUser.email}</p>
                  </div>
                  <button 
                    onClick={handleLogout}
                    className="w-full flex items-center space-x-3 px-4 py-3 text-sm font-semibold text-red-400 hover:bg-red-400/10 rounded-xl transition-colors"
                  >
                    <LogOut size={16} />
                    <span>Logout</span>
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {searchResults && (
          <div className="fixed inset-0 top-20 z-40 bg-google-bg/95 backdrop-blur-md overflow-y-auto animate-fade">
            <div className="max-w-6xl mx-auto p-8 md:p-12">
              <div className="flex justify-between items-end mb-12">
                <div>
                  <h2 className="text-3xl font-bold text-google-dark">Catalog Results</h2>
                  <p className="text-google-gray text-xs font-bold uppercase tracking-widest mt-2">Showing matches for "{searchQuery}"</p>
                </div>
                <button 
                  onClick={clearSearch}
                  className="px-6 py-2.5 rounded-full border border-google-border text-[10px] font-bold uppercase tracking-widest hover:bg-google-surface transition-all flex items-center"
                >
                  <X size={14} className="mr-2" /> Close Results
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {searchResults.map((item) => (
                  <div key={item.id} className="group bg-google-surface rounded-2xl border border-google-border overflow-hidden hover:border-google-blue transition-all shadow-sm flex flex-col">
                    <div className="aspect-square bg-google-bg relative overflow-hidden">
                      <img 
                        src={item.imageUrl} 
                        alt={item.name} 
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" 
                        onError={(e) => {
                          (e.target as HTMLImageElement).src = `https://placehold.co/400x400/1e1e1e/8ab4f8?text=${encodeURIComponent(item.name)}`;
                        }}
                      />
                      <div className="absolute top-4 right-4">
                        <span className="bg-google-blue/90 text-google-bg px-3 py-1 rounded-full text-sm font-bold shadow-lg">
                          ${item.price.toLocaleString()}
                        </span>
                      </div>
                    </div>
                    <div className="p-6 flex-1 flex flex-col justify-between">
                      <div className="space-y-2 mb-6">
                        <h4 className="font-bold text-google-dark text-lg leading-tight">{item.name}</h4>
                        <p className="text-xs text-google-gray leading-relaxed line-clamp-3">{item.description}</p>
                      </div>
                      <div className="flex items-center space-x-2">
                        <a 
                          href={item.productUrl} 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          className="flex-1 bg-google-blue text-google-bg py-3 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:brightness-110 transition-all flex items-center justify-center"
                        >
                          <ShoppingCart size={14} className="mr-2" /> View on Store
                        </a>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {searchResults.length === 0 && (
                <div className="py-20 text-center opacity-40">
                  <Search size={48} className="mx-auto mb-4" />
                  <p className="text-sm font-bold uppercase tracking-widest">No matching artifacts found in catalog</p>
                </div>
              )}
            </div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-6 md:p-12 lg:p-16 custom-scrollbar">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Download, ShoppingBag, Plus, ImageIcon, CheckCircle2, ChevronRight, Wand2, ShieldCheck, RefreshCcw, Layout, AlertTriangle, Crown, Star } from 'lucide-react';
import { remodelImage } from '../services/geminiService';
import { GeneratedImage, DESIGN_PRESETS, UserAccount, ProductItem } from '../types';
import { Button } from './Button';
import { ShopLookModal } from './ShopLookModal';

interface RemodelerProps {
  onImageGenerated: (image: GeneratedImage) => void;
  initialImage?: string | null;
  onClearInitial?: () => void;
  currentUser: UserAccount | null;
  onSaveProducts?: (imageUrl: string, products: ProductItem[]) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated, initialImage, onClearInitial, currentUser, onSaveProducts }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(initialImage || null);
  const [instruction, setInstruction] = useState('');
  const [projectName, setProjectName] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialImage) {
      setPreviewUrl(initialImage);
      setResultImage(null);
    }
  }, [initialImage]);

  const getRecentRendersCount = () => {
    if (!currentUser || currentUser.role !== 'Client') return 0;
    const now = Date.now();
    const twentyFourHoursAgo = now - 24 * 60 * 60 * 1000;
    const history = currentUser.renderTimestamps || [];
    return history.filter(ts => ts > twentyFourHoursAgo).length;
  };

  const rendersUsedToday = getRecentRendersCount();
  const isQuotaReached = currentUser?.role === 'Client' && rendersUsedToday >= 2;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
        if (onClearInitial) onClearInitial();
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async () => {
    if (isQuotaReached) return;
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;
    setIsProcessing(true);
    try {
      const styleContext = selectedStyle ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt : '';
      const fullInstruction = `${instruction}. ${styleContext}. Budget Target: $${budget}`.trim();
      const outputBase64 = await remodelImage(previewUrl, fullInstruction);
      setResultImage(outputBase64);
      onImageGenerated({
        id: Date.now().toString(),
        url: outputBase64,
        prompt: fullInstruction,
        mode: 'edit',
        timestamp: Date.now(),
        projectName: projectName || 'Untitled Iteration'
      });
    } catch (error) {
      alert("Something went wrong with the remodel. Please ensure your prompt focuses on home design.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setPreviewUrl(null);
    setResultImage(null);
    setSelectedFile(null);
    setProjectName('');
    if (onClearInitial) onClearInitial();
  };

  return (
    <div className="max-w-6xl mx-auto animate-fade">
      <header className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <div className="flex items-center space-x-2 mb-2">
            <ShieldCheck size={18} className="text-google-blue" />
            <span className="text-xs font-bold text-google-blue uppercase tracking-widest">Industry Specific Engine</span>
          </div>
          <h2 className="text-3xl font-semibold text-google-dark mb-2">
            {initialImage ? 'Refine Iteration' : 'Remodel your Space'}
          </h2>
          <p className="text-google-gray font-medium text-base">Let PRHOMZ AI Designer curate Furnishings and Decor Changes</p>
        </div>
        {previewUrl && (
          <button 
            onClick={handleReset}
            className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-google-gray hover:text-google-dark transition-colors"
          >
            <RefreshCcw size={14} />
            <span>Upload New Photo</span>
          </button>
        )}
      </header>

      {currentUser?.role === 'Client' && (
        <div className={`mb-8 p-6 rounded-2xl border flex items-center justify-between ${isQuotaReached ? 'bg-red-400/10 border-red-400/30' : 'bg-google-blue/5 border-google-blue/20'}`}>
          <div className="flex items-center space-x-4">
            {isQuotaReached ? <AlertTriangle className="text-red-400" size={24} /> : <Crown className="text-google-blue" size={24} />}
            <div>
              <p className={`text-sm font-bold uppercase tracking-widest ${isQuotaReached ? 'text-red-400' : 'text-google-blue'}`}>
                {isQuotaReached ? 'Daily Quota Reached' : 'Essential Account Quota'}
              </p>
              <p className="text-xs text-google-gray font-medium mt-0.5">
                {isQuotaReached 
                  ? 'Free users are limited to 2 transformations per 24h. Upgrade for unlimited access.' 
                  : `${rendersUsedToday}/2 transformations used in the last 24h.`}
              </p>
            </div>
          </div>
          {!isQuotaReached && (
            <div className="flex h-2 w-32 bg-google-bg rounded-full overflow-hidden border border-google-border">
              <div 
                className="h-full bg-google-blue transition-all duration-1000" 
                style={{ width: `${(rendersUsedToday / 2) * 100}%` }}
              />
            </div>
          )}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        <div className="lg:col-span-4 space-y-8">
          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-4 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider flex items-center">
              <Layout size={16} className="mr-2" /> Project Meta
            </h3>
            <input 
              type="text"
              value={projectName}
              onChange={(e) => setProjectName(e.target.value)}
              placeholder="e.g. Master Suite Revamp"
              className="w-full bg-google-bg border border-google-border rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-google-blue focus:outline-none text-google-dark placeholder-google-gray transition-all"
            />
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl overflow-hidden p-6 space-y-6 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Step 1: Upload Room Photo</h3>
            <div 
              onClick={() => !isQuotaReached && fileInputRef.current?.click()}
              className={`
                relative h-56 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all
                ${previewUrl ? 'border-google-blue bg-google-blue/10' : 'border-google-border bg-google-bg hover:bg-google-surface'}
                ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {previewUrl ? (
                <div className="relative w-full h-full group">
                  <img src={previewUrl} alt="Preview" className="w-full h-full object-cover rounded-lg opacity-90" />
                  {!isQuotaReached && (
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity rounded-lg">
                      <span className="text-xs font-bold text-white uppercase tracking-widest">Change Photo</span>
                    </div>
                  )}
                </div>
              ) : (
                <div className="text-center p-6 space-y-2">
                  <div className="w-12 h-12 bg-google-surface rounded-full flex items-center justify-center mx-auto shadow-sm border border-google-border">
                    <Plus className="w-5 h-5 text-google-blue" />
                  </div>
                  <p className="text-sm font-medium text-google-gray">Select interior photo</p>
                </div>
              )}
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            </div>
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-6 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Step 2: Design Direction</h3>
            <div className="grid grid-cols-2 gap-3">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  disabled={isQuotaReached}
                  onClick={() => setSelectedStyle(prev => prev === style.id ? '' : style.id)}
                  className={`
                    px-3 py-3 text-xs font-semibold border rounded-lg transition-all text-left relative overflow-hidden
                    ${selectedStyle === style.id ? 'bg-google-blue text-google-bg border-google-blue font-bold shadow-lg' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark hover:bg-google-surface'}
                    ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}
                  `}
                >
                  <span className="relative z-10">{style.label}</span>
                  {style.isTrending && (
                    <div className="absolute top-0 right-0 p-1">
                      <Star size={10} className={selectedStyle === style.id ? 'text-google-bg' : 'text-google-blue'} fill="currentColor" />
                    </div>
                  )}
                </button>
              ))}
            </div>
            <textarea
              value={instruction}
              disabled={isQuotaReached}
              onChange={(e) => setInstruction(e.target.value)}
              placeholder="Refine further: e.g. Swap sofa for velvet sectional, add gold accent lamps..."
              className={`w-full bg-google-bg border border-google-border rounded-xl p-4 text-sm focus:ring-2 focus:ring-google-blue focus:outline-none min-h-[120px] resize-none text-google-dark placeholder-google-gray leading-relaxed ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-6 shadow-sm">
            <div className="flex justify-between items-center">
              <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Furnishing Budget</h3>
              <span className="text-base font-bold text-google-dark">${budget.toLocaleString()}</span>
            </div>
            <input 
              type="range" min="500" max="50000" step="500" value={budget}
              disabled={isQuotaReached}
              onChange={(e) => setBudget(parseInt(e.target.value))}
              className={`w-full h-2 rounded-full cursor-pointer ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
          </section>

          <Button 
            onClick={handleRemodel} 
            isLoading={isProcessing} 
            className={`w-full rounded-xl py-4.5 text-base font-bold ${isQuotaReached ? 'bg-google-gray cursor-not-allowed' : ''}`}
            disabled={!previewUrl || (!instruction.trim() && !selectedStyle) || isQuotaReached}
          >
            <Wand2 className="w-5 h-5 mr-2" />
            {isQuotaReached ? 'Quota Reached' : initialImage ? 'Apply Refinements' : 'Apply Transformations'}
          </Button>
        </div>

        <div className="lg:col-span-8">
          <div className="bg-google-surface border border-google-border rounded-[2.5rem] overflow-hidden flex items-center justify-center min-h-[600px] relative group shadow-lg">
            {resultImage ? (
              <div className="w-full h-full relative">
                <img src={resultImage} alt="Remodeled" className="w-full h-full object-cover" />
                <div className="absolute inset-x-0 bottom-0 p-10 bg-gradient-to-t from-google-bg/95 to-transparent flex items-center justify-center space-x-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                  <Button onClick={() => setIsShopOpen(true)} className="rounded-full bg-google-dark text-google-bg hover:bg-white border-none px-10 py-4 text-sm font-bold shadow-2xl transition-all hover:scale-105 active:scale-95">
                    <ShoppingBag className="w-5 h-5 mr-2" />
                    Shop Furnishings
                  </Button>
                  <button 
                    onClick={() => {
                      const link = document.createElement('a');
                      link.href = resultImage;
                      link.download = 'remodel.png';
                      link.click();
                    }}
                    className="p-4 bg-google-surface/60 backdrop-blur-md text-google-dark rounded-full hover:bg-google-surface transition-all shadow-xl border border-google-border hover:scale-110 active:scale-90"
                  >
                    <Download size={24} />
                  </button>
                </div>
              </div>
            ) : (
              <div className="text-center p-20 space-y-8">
                {isProcessing ? (
                  <div className="flex flex-col items-center space-y-8">
                    <div className="w-16 h-16 border-4 border-google-border border-t-google-blue rounded-full animate-spin"></div>
                    <p className="text-sm font-bold text-google-gray animate-pulse font-mono tracking-widest">REDRAWING ROOM ARCHITECTURE...</p>
                  </div>
                ) : (
                  <div className="opacity-40 flex flex-col items-center space-y-6">
