  onSaveProducts?: (imageUrl: string, products: ProductItem[]) => void;
}

export const Remodeler: React.FC<RemodelerProps> = ({ onImageGenerated, initialImage, onClearInitial, currentUser, onSaveProducts }) => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(initialImage || null);
  const [instruction, setInstruction] = useState('');
  const [projectName, setProjectName] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<string>('');
  const [budget, setBudget] = useState(5000);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [generationTime, setGenerationTime] = useState<number | null>(null);
  const [activeTimer, setActiveTimer] = useState<number>(0);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (initialImage) {
      setPreviewUrl(initialImage);
      setResultImage(null);
      setGenerationTime(null);
    }
  }, [initialImage]);

  const startTimer = () => {
    setActiveTimer(0);
    const start = Date.now();
    timerIntervalRef.current = window.setInterval(() => {
      setActiveTimer((Date.now() - start) / 1000);
    }, 100);
  };

  const stopTimer = () => {
    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = null;
    }
  };

  const getRecentRendersCount = () => {
    if (!currentUser || currentUser.role !== 'Client') return 0;
    const now = Date.now();
    const twentyFourHoursAgo = now - 24 * 60 * 60 * 1000;
    const history = currentUser.renderTimestamps || [];
    return history.filter(ts => ts > twentyFourHoursAgo).length;
  };

  const rendersUsedToday = getRecentRendersCount();
  const isQuotaReached = currentUser?.role === 'Client' && rendersUsedToday >= 2;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = (ev) => {
        setPreviewUrl(ev.target?.result as string);
        setResultImage(null);
        setGenerationTime(null);
        if (onClearInitial) onClearInitial();
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemodel = async () => {
    if (isQuotaReached) return;
    if (!previewUrl || (!instruction.trim() && !selectedStyle)) return;
    setIsProcessing(true);
    setGenerationTime(null);
    startTimer();

    try {
      const styleContext = selectedStyle ? DESIGN_PRESETS.find(p => p.id === selectedStyle)?.prompt : '';
      const fullInstruction = `${instruction}. ${styleContext}. Budget Target: $${budget}`.trim();
      const outputBase64 = await remodelImage(previewUrl, fullInstruction);

      stopTimer();
      setGenerationTime(activeTimer);
      setResultImage(outputBase64);

      onImageGenerated({
        id: Date.now().toString(),
        url: outputBase64,
        prompt: fullInstruction,
        mode: 'edit',
        timestamp: Date.now(),
        projectName: projectName || 'Untitled Iteration'
      });
    } catch (error) {
      stopTimer();
      alert("Something went wrong with the remodel. Please ensure your prompt focuses on home design.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setPreviewUrl(null);
    setResultImage(null);
    setSelectedFile(null);
    setProjectName('');
    setGenerationTime(null);
    if (onClearInitial) onClearInitial();
  };

  return (
    <div className="max-w-6xl mx-auto animate-fade">
      <header className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <div className="flex items-center space-x-2 mb-2">
            <ShieldCheck size={18} className="text-google-blue" />
            <span className="text-xs font-bold text-google-blue uppercase tracking-widest">Industry Specific Engine</span>
          </div>
          <h2 className="text-3xl font-semibold text-google-dark mb-2">
            {initialImage ? 'Refine Iteration' : 'Remodel your Space'}
          </h2>
          <p className="text-google-gray font-medium text-base">Let PRHOMZ AI Designer curate Furnishings and Decor Changes</p>
        </div>
        {previewUrl && (
          <button 
            onClick={handleReset}
            className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-google-gray hover:text-google-dark transition-colors"
          >
            <RefreshCcw size={14} />
            <span>Upload New Photo</span>
          </button>
        )}
      </header>

      {currentUser?.role === 'Client' && (
        <div className={`mb-8 p-6 rounded-2xl border flex items-center justify-between ${isQuotaReached ? 'bg-red-400/10 border-red-400/30' : 'bg-google-blue/5 border-google-blue/20'}`}>
          <div className="flex items-center space-x-4">
            {isQuotaReached ? <AlertTriangle className="text-red-400" size={24} /> : <Crown className="text-google-blue" size={24} />}
            <div>
              <p className={`text-sm font-bold uppercase tracking-widest ${isQuotaReached ? 'text-red-400' : 'text-google-blue'}`}>
                {isQuotaReached ? 'Daily Quota Reached' : 'Essential Account Quota'}
              </p>
              <p className="text-xs text-google-gray font-medium mt-0.5">
                {isQuotaReached 
                  ? 'Free users are limited to 2 transformations per 24h. Upgrade for unlimited access.' 
                  : `${rendersUsedToday}/2 transformations used in the last 24h.`}
              </p>
            </div>
          </div>
          {!isQuotaReached && (
            <div className="flex h-2 w-32 bg-google-bg rounded-full overflow-hidden border border-google-border">
              <div 
                className="h-full bg-google-blue transition-all duration-1000" 
                style={{ width: `${(rendersUsedToday / 2) * 100}%` }}
              />
            </div>
          )}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        <div className="lg:col-span-4 space-y-8">
          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-4 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider flex items-center">
              <Layout size={16} className="mr-2" /> Project Meta
            </h3>
            <input 
              type="text"
              value={projectName}
              onChange={(e) => setProjectName(e.target.value)}
              placeholder="e.g. Master Suite Revamp"
              className="w-full bg-google-bg border border-google-border rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-google-blue focus:outline-none text-google-dark placeholder-google-gray transition-all"
            />
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl overflow-hidden p-6 space-y-6 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Step 1: Upload Room Photo</h3>
            <div 
              onClick={() => !isQuotaReached && fileInputRef.current?.click()}
              className={`
                relative h-56 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all
                ${previewUrl ? 'border-google-blue bg-google-blue/10' : 'border-google-border bg-google-bg hover:bg-google-surface'}
                ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {previewUrl ? (
                <div className="relative w-full h-full group">
                  <img src={previewUrl} alt="Preview" className="w-full h-full object-cover rounded-lg opacity-90" />
                  {!isQuotaReached && (
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity rounded-lg">
                      <span className="text-xs font-bold text-white uppercase tracking-widest">Change Photo</span>
                    </div>
                  )}
                </div>
              ) : (
                <div className="text-center p-6 space-y-2">
                  <div className="w-12 h-12 bg-google-surface rounded-full flex items-center justify-center mx-auto shadow-sm border border-google-border">
                    <Plus className="w-5 h-5 text-google-blue" />
                  </div>
                  <p className="text-sm font-medium text-google-gray">Select interior photo</p>
                </div>
              )}
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            </div>
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-6 shadow-sm">
            <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Step 2: Design Direction</h3>
            <div className="grid grid-cols-2 gap-3">
              {DESIGN_PRESETS.map((style) => (
                <button
                  key={style.id}
                  disabled={isQuotaReached}
                  onClick={() => setSelectedStyle(prev => prev === style.id ? '' : style.id)}
                  className={`
                    px-3 py-3 text-xs font-semibold border rounded-lg transition-all text-left relative overflow-hidden
                    ${selectedStyle === style.id ? 'bg-google-blue text-google-bg border-google-blue font-bold shadow-lg' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark hover:bg-google-surface'}
                    ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}
                  `}
                >
                  <span className="relative z-10">{style.label}</span>
                  {style.isTrending && (
                    <div className="absolute top-0 right-0 p-1">
                      <Star size={10} className={selectedStyle === style.id ? 'text-google-bg' : 'text-google-blue'} fill="currentColor" />
                    </div>
                  )}
                </button>
              ))}
            </div>
            <textarea
              value={instruction}
              disabled={isQuotaReached}
              onChange={(e) => setInstruction(e.target.value)}
              placeholder="Refine further: e.g. Swap sofa for velvet sectional, add gold accent lamps..."
              className={`w-full bg-google-bg border border-google-border rounded-xl p-4 text-sm focus:ring-2 focus:ring-google-blue focus:outline-none min-h-[120px] resize-none text-google-dark placeholder-google-gray leading-relaxed ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
          </section>

          <section className="bg-google-surface border border-google-border rounded-2xl p-6 space-y-6 shadow-sm">
            <div className="flex justify-between items-center">
              <h3 className="text-sm font-bold text-google-gray uppercase tracking-wider">Furnishing Budget</h3>
              <span className="text-base font-bold text-google-dark">${budget.toLocaleString()}</span>
            </div>
            <input 
              type="range" min="500" max="50000" step="500" value={budget}
              disabled={isQuotaReached}
              onChange={(e) => setBudget(parseInt(e.target.value))}
              className={`w-full h-2 rounded-full cursor-pointer ${isQuotaReached ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
          </section>

          <Button 
            onClick={handleRemodel} 
            isLoading={isProcessing} 
            className={`w-full rounded-xl py-4.5 text-base font-bold ${isQuotaReached ? 'bg-google-gray cursor-not-allowed' : ''}`}
            disabled={!previewUrl || (!instruction.trim() && !selectedStyle) || isQuotaReached}
          >
            <Wand2 className="w-5 h-5 mr-2" />
            {isQuotaReached ? 'Quota Reached' : initialImage ? 'Apply Refinements' : 'Apply Transformations'}
          </Button>
        </div>

        <div className="lg:col-span-8">
          <div className="bg-google-surface border border-google-border rounded-[2.5rem] overflow-hidden flex items-center justify-center min-h-[600px] relative group shadow-lg">
            {resultImage ? (
              <div className="w-full h-full relative">
                <img src={resultImage} alt="Remodeled" className="w-full h-full object-cover" />
                <div className="absolute top-6 left-6 bg-google-bg/80 backdrop-blur-md px-4 py-2 rounded-xl border border-google-border flex items-center space-x-2 text-google-blue shadow-lg">
                  <Clock size={14} />
                  <span className="text-xs font-bold uppercase tracking-widest font-mono">Transformed in {generationTime?.toFixed(1)}s</span>
                </div>
                <div className="absolute inset-x-0 bottom-0 p-10 bg-gradient-to-t from-google-bg/95 to-transparent flex items-center justify-center space-x-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                  <Button onClick={() => setIsShopOpen(true)} className="rounded-full bg-google-dark text-google-bg hover:bg-white border-none px-10 py-4 text-sm font-bold shadow-2xl transition-all hover:scale-105 active:scale-95">
                    <ShoppingBag className="w-5 h-5 mr-2" />
                    Shop Furnishings
                  </Button>
                  <button 
                    onClick={() => {
                      const link = document.createElement('a');
                      link.href = resultImage;
                      link.download = 'remodel.png';
                      link.click();
                    }}
                    className="p-4 bg-google-surface/60 backdrop-blur-md text-google-dark rounded-full hover:bg-google-surface transition-all shadow-xl border border-google-border hover:scale-110 active:scale-90"
                  >
                    <Download size={24} />
                  </button>
                </div>
              </div>
            ) : (
              <div className="text-center p-20 space-y-8">
                {isProcessing ? (
                  <div className="flex flex-col items-center space-y-8">
                    <div className="w-16 h-16 border-4 border-google-border border-t-google-blue rounded-full animate-spin"></div>
                    <div className="flex flex-col items-center space-y-2">
                       <p className="text-sm font-bold text-google-gray animate-pulse font-mono tracking-widest">REDRAWING ROOM ARCHITECTURE...</p>
                       <span className="text-google-blue font-mono font-bold text-lg">{activeTimer.toFixed(1)}s</span>
                    </div>
                  </div>
                ) : (
                  <div className="opacity-40 flex flex-col items-center space-y-6">
                    <div className="w-24 h-24 border-2 border-dashed border-google-gray rounded-full flex items-center justify-center">
                      <ImageIcon className="w-10 h-10 text-google-gray" />
                    </div>
                    <p className="text-base font-bold text-google-gray uppercase tracking-widest">
                      {isQuotaReached ? 'Daily Quota Reached' : 'Awaiting Interior Scene'}
                    </p>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {resultImage && <ShopLookModal image={resultImage} isOpen={isShopOpen} onClose={() => setIsShopOpen(false)} budget={budget} onSaveProducts={(products) => onSaveProducts?.(resultImage, products)} />}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { X, ShoppingBag, Loader2, RefreshCw, Package, ExternalLink, Zap, Bookmark, Scan, ShieldCheck, BadgeCheck, CheckCircle2, Clock } from 'lucide-react';
import { ProductItem } from '../types';
import { generateProductList, swapProduct } from '../services/geminiService';
import { Button } from './Button';
import { SHOPIFY_STORE_URL } from '../services/dataService';

interface ShopLookModalProps {
  image: string;
  isOpen: boolean;
  onClose: () => void;
  budget?: number;
  onSaveProducts?: (products: ProductItem[]) => void;
}

export const ShopLookModal: React.FC<ShopLookModalProps> = ({ image, isOpen, onClose, budget, onSaveProducts }) => {
  const [products, setProducts] = useState<ProductItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selections, setSelections] = useState<Record<string, string>>({});
  const [swappingIds, setSwappingIds] = useState<Set<string>>(new Set());
  const [isSaved, setIsSaved] = useState(false);
  const [analysisTime, setAnalysisTime] = useState<number | null>(null);
  const [activeTimer, setActiveTimer] = useState<number>(0);

  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (isOpen && image) {
      loadProducts();
    } else {
      setProducts([]);
      setSelections({});
      setSwappingIds(new Set());
      setIsSaved(false);
      setAnalysisTime(null);
      stopTimer();
    }
  }, [isOpen, image]);

  const startTimer = () => {
    setActiveTimer(0);
    const start = Date.now();
    timerIntervalRef.current = window.setInterval(() => {
      setActiveTimer((Date.now() - start) / 1000);
    }, 100);
  };

  const stopTimer = () => {
    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = null;
    }
  };

  const loadProducts = async () => {
    setLoading(true);
    setAnalysisTime(null);
    startTimer();

    try {
      const items = await generateProductList(image);
      stopTimer();
      setAnalysisTime(activeTimer);
      setProducts(items);
      const initialSelections: Record<string, string> = {};
      items.forEach(item => { if (item.colors.length > 0) initialSelections[item.id] = item.colors[0]; });
      setSelections(initialSelections);
    } catch (error) {
      stopTimer();
      console.error("Failed to load products", error);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Curation Logic: strictly enforce budget based on source price.
   */
  const budgetCompliantProducts = useMemo(() => {
    if (budget === undefined || budget === 0) return products;
    let runningTotal = 0;
    return products.filter(product => {
      if (runningTotal + product.price <= budget) {
        runningTotal += product.price;
        return true;
      }
      return false;
    });
  }, [products, budget]);

  const handleColorSelect = (productId: string, color: string) => {
    setSelections(prev => ({ ...prev, [productId]: color }));
  };

  const handleSourcingAction = (item: ProductItem) => {
    if (item.productUrl) {
      window.open(item.productUrl, '_blank');
    } else {
      window.open(`${SHOPIFY_STORE_URL}/search?q=${encodeURIComponent(item.name)}`, '_blank');
    }
  };

  const handleSaveSelection = () => {
    if (onSaveProducts) {
      onSaveProducts(budgetCompliantProducts);
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 2000);
    }
  };

  const handleSwap = async (productId: string) => {
    const productToSwap = products.find(p => p.id === productId);
    if (!productToSwap) return;
    setSwappingIds(prev => new Set(prev).add(productId));
    try {
      const newProduct = await swapProduct(image, productToSwap);
      setProducts(prev => prev.map(p => p.id === productId ? newProduct : p));
    } catch (error) { 
      console.error("Swap failed", error); 
    } finally { 
      setSwappingIds(prev => { 
        const next = new Set(prev); 
        next.delete(productId); 
        return next; 
      }); 
    }
  };

  if (!isOpen) return null;

  const currentTotal = budgetCompliantProducts.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 overflow-hidden">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={onClose} />

      <div className="relative bg-google-bg w-full max-w-6xl h-[90vh] rounded-[2rem] shadow-2xl border border-google-border flex flex-col md:flex-row overflow-hidden animate-fade">
        <button onClick={onClose} className="absolute top-6 right-6 z-50 p-3 text-google-gray hover:text-google-dark hover:bg-google-surface rounded-full transition-all">
          <X size={28} />
        </button>

        <div className="w-full md:w-96 bg-google-surface relative hidden md:flex flex-col border-r border-google-border p-10 justify-between">
          <div className="space-y-6">
            <div className="flex items-center space-x-2 text-google-blue">
               <ShieldCheck size={20} />
               <h3 className="text-2xl font-bold uppercase tracking-tight">PRHOMZ SYNC</h3>
            </div>
            <p className="text-sm text-google-gray leading-relaxed">
              Every artifact detected is matched against the <b>Live Catalog</b> to ensure source-accurate pricing.
              <br/><br/>
              <b>Budget Threshold:</b> ${budget?.toLocaleString()}
            </p>
            {budget !== undefined && (
              <div className="pt-6 border-t border-google-border">
                <span className="text-xs font-bold text-google-gray uppercase tracking-widest block mb-2">Project Threshold</span>
                <span className="text-2xl font-bold text-google-blue">${budget.toLocaleString()}</span>
              </div>
            )}
          </div>

          <div className="rounded-2xl overflow-hidden border border-google-border aspect-square relative group shadow-inner">
            <img src={image} alt="Reference" className="w-full h-full object-cover" />
            {loading && (
               <div className="absolute inset-0 bg-google-blue/20 backdrop-blur-sm flex flex-col items-center justify-center text-google-blue">
                  <Scan size={48} className="animate-pulse mb-4" />
                  <span className="text-xs font-black uppercase tracking-[0.2em]">Syncing Feed...</span>
                  <span className="mt-2 text-lg font-mono font-bold">{activeTimer.toFixed(1)}s</span>
               </div>
            )}
          </div>

          <div className="flex items-center space-x-3 opacity-60">
             <Package size={18} />
             <span className="text-xs font-bold uppercase tracking-[0.2em]">PRHOMZ LIVE FEED</span>
          </div>
        </div>

        <div className="flex-1 flex flex-col h-full bg-google-bg overflow-hidden">
          <div className="p-8 border-b border-google-border flex items-center justify-between bg-google-bg/50">
            <div className="flex flex-col">
              <h3 className="text-xl font-bold text-google-dark">Spatial Catalog Results</h3>
              <div className="flex items-center space-x-3 mt-2">
                <div className="flex items-center space-x-2 px-3 py-1 rounded-lg bg-google-lightBlue text-google-blue border border-google-blue/20">
                  <BadgeCheck size={14} />
                  <span className="text-xs font-bold uppercase tracking-tight">Direct Source Pricing</span>
                </div>
                {analysisTime !== null && (
                  <div className="flex items-center space-x-2 px-3 py-1 rounded-lg bg-google-surface text-google-gray border border-google-border">
                    <Clock size={12} />
                    <span className="text-[10px] font-bold uppercase tracking-tight font-mono">Synced in {analysisTime.toFixed(1)}s</span>
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar">
            {loading ? (
              <div className="h-full flex flex-col items-center justify-center space-y-6">
                <div className="relative">
                  <Loader2 className="w-12 h-12 animate-spin text-google-blue" />
                  <Scan className="w-6 h-6 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-google-blue" />
                </div>
                <div className="text-center">
                  <p className="text-sm font-bold text-google-dark uppercase tracking-widest mb-2">Source Integration</p>
                  <p className="text-xs text-google-gray font-medium">Matching vision to physical inventory nodes...</p>
                  <div className="mt-4 text-google-blue font-mono font-bold text-xl">{activeTimer.toFixed(1)}s</div>
                </div>
              </div>
            ) : budgetCompliantProducts.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center opacity-40">
                <ShoppingBag size={64} />
                <p className="text-sm font-bold mt-4 uppercase tracking-widest">No Matches</p>
                <p className="text-xs mt-2">No items found within your threshold.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {budgetCompliantProducts.map((item) => (
                  <div key={item.id} className="bg-google-surface p-6 rounded-2xl border border-google-border flex flex-col hover:border-google-blue/40 transition-all group">
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div className="flex justify-between items-start">
                        <div className="max-w-[70%]">
                          <div className="flex items-center space-x-3 mb-2">
                             {swappingIds.has(item.id) ? (
                               <Loader2 size={16} className="text-google-blue animate-spin" />
                             ) : (
                               <Package size={16} className="text-google-blue opacity-50" />
                             )}
                             <h4 className="font-bold text-google-dark text-lg leading-tight truncate">{item.name}</h4>
                             {item.isSynced && (
                               <div className="flex items-center space-x-1 text-google-blue bg-google-blue/5 px-2 py-0.5 rounded border border-google-blue/10 flex-shrink-0">
                                 <BadgeCheck size={12} />
                                 <span className="text-[9px] font-black uppercase tracking-widest">Source Accurate</span>
                               </div>
                             )}
                          </div>
                          <p className="text-sm text-google-gray mt-1 line-clamp-2 leading-relaxed">{item.description}</p>
                        </div>
                        <div className="text-right">
                          <span className="text-xl font-bold text-google-blue block whitespace-nowrap">${item.price.toLocaleString()}</span>
                          <span className="text-[9px] font-bold uppercase text-google-gray tracking-tighter">Live Price</span>
                        </div>
                      </div>

                      <div className="flex items-center justify-between mt-6">
                        <div className="flex gap-2">
                          {item.colors.map(color => (
                            <button key={color} onClick={() => handleColorSelect(item.id, color)} className={`px-3 py-1 text-xs font-bold rounded-lg border transition-all ${selections[item.id] === color ? 'bg-google-blue text-google-bg border-google-blue' : 'bg-google-bg border-google-border text-google-gray hover:text-google-dark'}`}>
                              {color}
                            </button>
                          ))}
                        </div>
                        <div className="flex space-x-3">
                          <button onClick={() => handleSwap(item.id)} className="p-2 text-google-gray border border-google-border rounded-xl hover:text-google-blue hover:bg-google-bg transition-all" title="Alternative Piece"><RefreshCw size={16} /></button>
                          <button 
                            onClick={() => handleSourcingAction(item)} 
                            className="px-6 py-2.5 bg-google-blue text-google-bg rounded-xl text-xs font-bold flex items-center shadow-xl hover:brightness-110 transition-all hover:scale-105 active:scale-95"
                          >
                            <ExternalLink size={14} className="mr-2" /> 
                            Buy Now
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
