    if (score > highestScore) {
      highestScore = score;
      bestLocalMatch = item;
    }
  }

  if (bestLocalMatch && highestScore >= 10) {
    return {
      ...bestLocalMatch,
      isSynced: true // Flag as verified from the local 'Atelier' cache
    };
